const Q_SR_GENMATHS=[{"id": "srg111001", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Financial Mathematics — Simple Interest", "difficulty": "hard", "style": "standard", "paper": "G11-G1", "q": "$5000 is invested at a simple interest rate of 4.5% per annum for 3 years. How much interest is earned?", "options": ["$225", "$450", "$675", "$900"], "answer": 2, "exp": "Step 1: Simple interest = P × R × T = 5000 × 0.045 × 3. Step 2: 5000 × 0.045 = 225, then 225 × 3 = $675.", "hint": "Use the simple interest formula: Principal × Rate × Time."}, {"id": "srg111002", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Financial Mathematics — Compound Interest", "difficulty": "hard", "style": "standard", "paper": "G11-G1", "q": "$8000 is invested at 5% per annum, compounded annually, for 4 years. What is the value of the investment, to the nearest cent?", "options": ["$9600.00", "$9724.05", "$9800.00", "$10,000.00"], "answer": 1, "exp": "Step 1: Use A = P(1+r)ⁿ = 8000 × (1.05)⁴. Step 2: This gives $9724.05.", "hint": "Use the compound interest formula, raising (1 + rate) to the power of the number of years."}, {"id": "srg111003", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Financial Mathematics — Depreciation", "difficulty": "hard", "style": "standard", "paper": "G11-G1", "q": "A car worth $25,000 depreciates using the flat rate (straight-line) method at 12% of its original value per year. What is its value after 5 years?", "options": ["$9000", "$10,000", "$12,500", "$15,000"], "answer": 1, "exp": "Step 1: Annual depreciation = 12% of $25,000 = $3000. Step 2: Total depreciation over 5 years = 5 × $3000 = $15,000. Step 3: Value = $25,000 − $15,000 = $10,000.", "hint": "With flat rate depreciation, the same dollar amount is subtracted every year."}, {"id": "srg111004", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Financial Mathematics — Depreciation", "difficulty": "hard", "style": "standard", "paper": "G11-G1", "q": "The same $25,000 car instead depreciates using the reducing balance (declining value) method at 12% per year. What is its approximate value after 5 years?", "options": ["$10,000.00", "$11,500.00", "$13,193.30", "$15,000.00"], "answer": 2, "exp": "Step 1: Use A = P(1−r)ⁿ = 25000 × (0.88)⁵. Step 2: This gives approximately $13,193.30.", "hint": "With reducing balance depreciation, each year's depreciation is calculated on the previous year's reduced value."}, {"id": "srg111005", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Financial Mathematics — Depreciation", "difficulty": "hard", "style": "standard", "paper": "G11-G1", "q": "Which depreciation method results in a higher asset value after several years: flat rate or reducing balance, assuming the same initial rate?", "options": ["flat rate always results in a higher value", "reducing balance always results in a higher value", "they always result in exactly the same value", "it depends entirely on the asset type, with no general pattern"], "answer": 1, "exp": "Reducing balance depreciation generally results in a higher remaining value after several years, since each year's depreciation amount shrinks as it's calculated on an already-reduced balance.", "hint": "Think about how the depreciation amount changes each year under each method."}, {"id": "srg111006", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Financial Mathematics — Interest Rates", "difficulty": "hard", "style": "standard", "paper": "G11-G1", "q": "What is the difference between 'nominal' and 'effective' interest rates?", "options": ["they always refer to exactly the same rate", "the nominal rate is the stated annual rate, while the effective rate accounts for the effect of compounding more than once per year", "the effective rate is always lower than the nominal rate", "nominal rates only apply to loans, not investments"], "answer": 1, "exp": "The nominal rate is the stated annual interest rate, while the effective annual rate accounts for the actual effect of compounding (e.g. monthly or quarterly), which can result in a higher actual return than the nominal rate suggests.", "hint": "Think about how compounding more frequently than once a year affects the true rate of return."}, {"id": "srg111007", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Financial Mathematics — Compound Interest", "difficulty": "hard", "style": "standard", "paper": "G11-G1", "q": "A $6000 loan is taken out at 8% per annum, compounded monthly, for 2 years with no repayments made. What is the monthly interest rate used in calculations?", "options": ["0.0067 (8%/12)", "0.08 (8%)", "0.16 (8% × 2)", "0.96 (8% × 12)"], "answer": 0, "exp": "When interest is compounded monthly, the annual rate is divided by 12: 0.08 ÷ 12 ≈ 0.0067 per month.", "hint": "Divide the annual rate by the number of compounding periods per year."}, {"id": "srg111008", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Financial Mathematics — Compound Interest", "difficulty": "hard", "style": "standard", "paper": "G11-G1", "q": "Using the loan from the previous question ($6000 at 8% p.a. compounded monthly for 2 years, no repayments), what is the approximate final amount owed?", "options": ["$6480.00", "$6900.00", "$7037.33", "$7200.00"], "answer": 2, "exp": "Step 1: Monthly rate = 0.08/12. Step 2: Number of months = 24. Step 3: A = 6000 × (1 + 0.08/12)²⁴ ≈ $7037.33.", "hint": "Use the compound interest formula with the monthly rate and the total number of months."}, {"id": "srg111009", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Financial Mathematics — Annuities", "difficulty": "hard", "style": "standard", "paper": "G11-G1", "q": "What is an 'annuity' in financial mathematics?", "options": ["a single, one-off payment", "a series of regular, equal payments made over time, such as loan repayments or retirement savings contributions", "a type of insurance policy only", "a synonym for simple interest"], "answer": 1, "exp": "An annuity is a series of regular, equal payments made over time, such as loan repayments, retirement savings contributions, or regular investment deposits.", "hint": "Think about regular, repeated payments, rather than a single lump sum."}, {"id": "srg111010", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Financial Mathematics — Percentage Growth", "difficulty": "hard", "style": "standard", "paper": "G11-G1", "q": "A salary of $65,000 increases by 3% each year. What will the salary be after 2 years, to the nearest dollar?", "options": ["$68,950", "$68,958", "$68,985", "$69,000"], "answer": 1, "exp": "Step 1: Use A = P(1+r)ⁿ = 65000 × (1.03)². Step 2: This gives $68,958.50, rounding to $68,958 (or $68,959 depending on rounding convention) — closest listed value is $68,958.", "hint": "Use the compound growth formula, treating the annual salary increase like compound interest."}, {"id": "srg111011", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Financial Mathematics — Loans", "difficulty": "hard", "style": "standard", "paper": "G11-G1", "q": "A $400,000 home loan has a reducing balance of $380,000 after the first year, with $32,000 paid in repayments. Approximately how much of that $32,000 went toward interest rather than reducing the principal?", "options": ["$8,000", "$12,000", "$20,000", "$32,000"], "answer": 1, "exp": "Step 1: Principal reduced = 400,000 − 380,000 = $20,000. Step 2: Interest paid = total repayments − principal reduction = 32,000 − 20,000 = $12,000.", "hint": "Subtract how much the loan balance actually decreased from the total amount repaid."}, {"id": "srg111012", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Financial Mathematics — Loans", "difficulty": "hard", "style": "standard", "paper": "G11-G1", "q": "Which of these best describes a 'reducing balance loan'?", "options": ["a loan where the interest charged is calculated on the original loan amount throughout the entire term", "a loan where interest is calculated on the outstanding (remaining) balance, which decreases as repayments are made", "a loan with no interest charged at all", "a loan that can never be paid off early"], "answer": 1, "exp": "A reducing balance loan calculates interest on the outstanding balance, which decreases over time as repayments are made, meaning less interest is charged as the loan is paid down.", "hint": "Think about interest being calculated on what's still owed, not the original amount borrowed."}, {"id": "srg111013", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Financial Mathematics — Simple Interest", "difficulty": "hard", "style": "standard", "paper": "G11-G1", "q": "$12,000 is invested at 6% p.a. simple interest. How many years will it take to earn $3600 in interest?", "options": ["3 years", "4 years", "5 years", "6 years"], "answer": 2, "exp": "Step 1: Using I = PRT, rearrange to find T: T = I ÷ (P × R) = 3600 ÷ (12000 × 0.06). Step 2: 3600 ÷ 720 = 5 years.", "hint": "Rearrange the simple interest formula to solve for time."}, {"id": "srg111014", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Financial Mathematics — Compound Interest", "difficulty": "hard", "style": "standard", "paper": "G11-G1", "q": "An investment of $10,000 grows to $14,802.44 after 8 years of annual compounding. Approximately what annual interest rate was used?", "options": ["3%", "4%", "5%", "6%"], "answer": 2, "exp": "Step 1: 14802.44/10000 = 1.480244. Step 2: Taking the 8th root: (1.480244)^(1/8) ≈ 1.05, meaning the rate is approximately 5%.", "hint": "Divide the final amount by the initial amount, then take the appropriate root to estimate the rate."}, {"id": "srg111015", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Financial Mathematics — Comparing Costs", "difficulty": "hard", "style": "standard", "paper": "G11-G1", "q": "Which of these correctly describes 'unit cost' when comparing the value of products of different sizes?", "options": ["the total price of the product regardless of size", "the price of the product divided by the quantity (e.g. price per 100 g or price per litre), allowing fair comparison", "the size of the product only", "a fixed amount added to every product's price"], "answer": 1, "exp": "Unit cost is the price divided by quantity (such as price per 100 g or per litre), allowing a fair comparison between products of different sizes or packaging.", "hint": "Think about dividing price by quantity to compare products fairly, regardless of package size."}, {"id": "srg111016", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Financial Mathematics — Payment Plans", "difficulty": "hard", "style": "standard", "paper": "G11-G1", "q": "A $1500 appliance is bought on a payment plan: a $300 deposit, then 12 monthly payments of $110. What is the total amount paid, and how much extra was paid compared to the cash price?", "options": ["total $1620, extra $120", "total $1620, extra $1320", "total $1320, extra $0", "total $1800, extra $300"], "answer": 0, "exp": "Step 1: Total paid = deposit + (monthly payment × 12) = 300 + (110×12) = 300+1320 = $1620. Step 2: Extra paid = 1620 − 1500 = $120.", "hint": "Add the deposit to the total of all monthly payments, then compare to the original cash price."}, {"id": "srg111017", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Financial Mathematics — Taxation", "difficulty": "hard", "style": "standard", "paper": "G11-G1", "q": "Which best describes 'GST' (Goods and Services Tax) as applied in Australia?", "options": ["a 5% tax added to all purchases without exception", "a 10% tax added to most goods and services, included in the displayed price", "a tax only applied to luxury items", "a tax that varies depending on the customer's income"], "answer": 1, "exp": "GST in Australia is a 10% tax applied to most goods and services, generally already included in the displayed price (with some exceptions, such as certain essential items).", "hint": "Think about the standard percentage rate of this tax in Australia."}, {"id": "srg111018", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Financial Mathematics — Taxation", "difficulty": "hard", "style": "standard", "paper": "G11-G1", "q": "A product's price, including 10% GST, is $77. What was the price before GST was added?", "options": ["$67.00", "$69.30", "$70.00", "$74.30"], "answer": 2, "exp": "Step 1: If the GST-inclusive price is 110% of the original, divide by 1.10: 77 ÷ 1.10 = $70.", "hint": "The GST-inclusive price represents 110% of the original price — divide by 1.10 to find the original."}, {"id": "srg111019", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Financial Mathematics — Interest", "difficulty": "hard", "style": "standard", "paper": "G11-G1", "q": "Which best describes 'simple interest' as opposed to 'compound interest'?", "options": ["simple interest is calculated only on the original principal each period, while compound interest is calculated on the accumulated balance (principal plus previous interest)", "simple interest always results in a higher return than compound interest", "compound interest is calculated only once, at the end of the term", "simple and compound interest always give identical results"], "answer": 0, "exp": "Simple interest is calculated only on the original principal each period, while compound interest is calculated on the accumulated balance, including previously earned interest, leading to faster growth over time.", "hint": "Think about whether interest is calculated only on the starting amount, or on a growing balance that includes previous interest."}, {"id": "srg111020", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Financial Mathematics — Depreciation", "difficulty": "hard", "style": "standard", "paper": "G11-G1", "q": "A car valued at $32,000 depreciates by 15% in its first year, then 15% of its new value in the second year. What is its value after 2 years?", "options": ["$22,560.00", "$23,120.00", "$24,320.00", "$25,600.00"], "answer": 1, "exp": "Step 1: After year 1: 32000 × 0.85 = $27,200. Step 2: After year 2: 27200 × 0.85 = $23,120.", "hint": "Apply the 15% depreciation twice in a row, using the new value each time."}, {"id": "srg111021", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Financial Mathematics — Budgeting", "difficulty": "hard", "style": "standard", "paper": "G11-G1", "q": "Which best describes the purpose of a 'budget' in personal financial planning?", "options": ["a budget has no real practical use", "a plan that tracks expected income and expenses over a period, helping manage spending and savings goals", "a legal requirement only for businesses", "a synonym for a bank statement"], "answer": 1, "exp": "A budget is a plan tracking expected income and expenses over a period, helping individuals or households manage spending and work toward savings goals.", "hint": "Think about a tool used to plan ahead for income and spending, rather than just recording what already happened."}, {"id": "srg111022", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Financial Mathematics — Income", "difficulty": "hard", "style": "standard", "paper": "G11-G1", "q": "A salary of $80,000 per year is paid fortnightly (26 pay periods per year). What is the approximate fortnightly pay, before tax?", "options": ["$1538.46", "$3076.92", "$6666.67", "$1666.67"], "answer": 1, "exp": "Step 1: Divide the annual salary by the number of pay periods: 80,000 ÷ 26. Step 2: This gives approximately $3076.92.", "hint": "Divide the annual salary by the number of fortnightly pay periods in a year."}, {"id": "srg111023", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Financial Mathematics — Simple Interest", "difficulty": "hard", "style": "standard", "paper": "G11-G1", "q": "Which of these is the correct formula for calculating simple interest (I), given principal (P), rate as a decimal (R), and time in years (T)?", "options": ["I = P + R + T", "I = P × R × T", "I = P × R ÷ T", "I = P ÷ (R × T)"], "answer": 1, "exp": "The simple interest formula is I = P × R × T, where P is the principal, R is the annual interest rate (as a decimal), and T is the time in years.", "hint": "Remember the standard simple interest formula: Principal × Rate × Time."}, {"id": "srg111024", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Financial Mathematics — Growth Rates", "difficulty": "hard", "style": "standard", "paper": "G11-G1", "q": "An investment triples in value over 15 years under compound interest. Using the rule of 72 as an estimate for doubling time, roughly how long would it take to DOUBLE at the same interest rate (this requires first estimating the rate from the tripling, then estimating doubling time)?", "options": ["about 5 years", "about 9 years", "about 12 years", "about 15 years"], "answer": 1, "exp": "Step 1: Tripling in 15 years suggests a rate around 7.6% (since 1.076^15 ≈ 3). Step 2: Using the rule of 72: doubling time ≈ 72 ÷ 7.6 ≈ 9.5 years, closest to 9 years.", "hint": "Estimate the annual rate from the tripling time first, then apply the rule of 72 for doubling time."}, {"id": "srg111025", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Financial Mathematics — Loans", "difficulty": "hard", "style": "standard", "paper": "G11-G1", "q": "Which of these would generally result in paying the LEAST total interest on a home loan, all else being equal?", "options": ["making only the minimum required monthly repayments", "making additional extra repayments whenever possible, reducing the principal faster", "extending the loan term as long as possible", "switching to interest-only repayments"], "answer": 1, "exp": "Making additional extra repayments reduces the outstanding principal faster, which reduces the amount of interest charged in future periods, generally minimising total interest paid over the life of the loan.", "hint": "Think about which strategy reduces the loan balance the fastest, since interest is calculated on the remaining balance."}, {"id": "srg112001", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Matrices — Addition", "difficulty": "hard", "style": "standard", "paper": "G11-G2", "q": "Given matrices A = [[2,3],[1,4]] and B = [[1,0],[2,1]], calculate A + B.", "options": ["[[3,3],[3,5]]", "[[1,3],[-1,3]]", "[[2,0],[2,4]]", "[[3,3],[1,5]]"], "answer": 0, "exp": "Add corresponding elements: top-left 2+1=3, top-right 3+0=3, bottom-left 1+2=3, bottom-right 4+1=5, giving [[3,3],[3,5]].", "hint": "Add the elements in matching positions from each matrix."}, {"id": "srg112002", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Matrices — Subtraction", "difficulty": "hard", "style": "standard", "paper": "G11-G2", "q": "Given matrices A = [[2,3],[1,4]] and B = [[1,0],[2,1]], calculate A − B.", "options": ["[[1,3],[-1,3]]", "[[3,3],[3,5]]", "[[1,3],[1,3]]", "[[-1,3],[1,-3]]"], "answer": 0, "exp": "Subtract corresponding elements: 2-1=1, 3-0=3, 1-2=-1, 4-1=3, giving [[1,3],[-1,3]].", "hint": "Subtract the elements in matching positions, being careful with the order (A minus B)."}, {"id": "srg112003", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Matrices — Multiplication", "difficulty": "hard", "style": "standard", "paper": "G11-G2", "q": "Given matrices A = [[2,3],[1,4]] and B = [[1,0],[2,1]], calculate A × B.", "options": ["[[8,3],[9,4]]", "[[2,0],[2,4]]", "[[6,3],[9,4]]", "[[8,3],[3,4]]"], "answer": 0, "exp": "Step 1: Top-left = (2×1)+(3×2) = 2+6 = 8. Step 2: Top-right = (2×0)+(3×1) = 0+3 = 3. Step 3: Bottom-left = (1×1)+(4×2) = 1+8 = 9. Step 4: Bottom-right = (1×0)+(4×1) = 0+4 = 4. Result: [[8,3],[9,4]].", "hint": "Multiply each row of A by each column of B, summing the products."}, {"id": "srg112004", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Matrices — Multiplication", "difficulty": "hard", "style": "standard", "paper": "G11-G2", "q": "Using the same matrices A and B, calculate B × A. Is this the same as A × B?", "options": ["[[2,3],[5,10]] — no, matrix multiplication is generally not commutative", "[[8,3],[9,4]] — yes, identical to A × B", "[[2,3],[5,10]] — yes, identical to A × B", "none of these"], "answer": 0, "exp": "Step 1: B × A = [[2,3],[5,10]], which is different from A × B = [[8,3],[9,4]]. Step 2: This confirms matrix multiplication is generally not commutative (order matters).", "hint": "Calculate B × A carefully and compare it to the earlier result for A × B."}, {"id": "srg112005", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Matrices — Determinant", "difficulty": "hard", "style": "standard", "paper": "G11-G2", "q": "What is the determinant of the matrix [[2,3],[1,4]]?", "options": ["5", "8", "11", "-5"], "answer": 0, "exp": "Step 1: For a 2×2 matrix [[a,b],[c,d]], determinant = ad − bc. Step 2: (2×4) − (3×1) = 8 − 3 = 5.", "hint": "Use the formula ad − bc for a 2×2 matrix."}, {"id": "srg112006", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Matrices — Determinant", "difficulty": "hard", "style": "standard", "paper": "G11-G2", "q": "What does it mean if a matrix has a determinant of 0?", "options": ["the matrix is a special 'identity' matrix", "the matrix is 'singular' and does not have an inverse", "the matrix can only be multiplied by itself", "the matrix must be a square matrix with all zero entries"], "answer": 1, "exp": "A matrix with a determinant of 0 is called 'singular', meaning it does not have an inverse — this is analogous to not being able to divide by zero.", "hint": "Think about why a matrix needs a non-zero determinant to be 'invertible'."}, {"id": "srg112007", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Matrices — Inverse", "difficulty": "hard", "style": "standard", "paper": "G11-G2", "q": "What is the inverse of the matrix A = [[2,3],[1,4]]? (Give your answer as a matrix of decimals.)", "options": ["[[0.8,-0.6],[-0.2,0.4]]", "[[0.4,-0.6],[-0.2,0.8]]", "[[4,-3],[-1,2]]", "[[0.2,0.3],[0.1,0.4]]"], "answer": 0, "exp": "Step 1: For A=[[a,b],[c,d]], the inverse is (1/det)×[[d,-b],[-c,a]]. Step 2: det=5, so inverse = (1/5)×[[4,-3],[-1,2]] = [[0.8,-0.6],[-0.2,0.4]].", "hint": "Use the formula for the inverse of a 2×2 matrix, dividing by the determinant."}, {"id": "srg112008", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Matrices — Determinant", "difficulty": "hard", "style": "standard", "paper": "G11-G2", "q": "What is the determinant of the matrix [[4,2],[3,1]]?", "options": ["-2", "2", "10", "-10"], "answer": 0, "exp": "Step 1: determinant = ad − bc = (4×1) − (2×3). Step 2: 4 − 6 = -2.", "hint": "Use the formula ad − bc, being careful with the order of subtraction."}, {"id": "srg112009", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Matrices — Scalar Multiplication", "difficulty": "hard", "style": "standard", "paper": "G11-G2", "q": "If matrix C = [[4,2],[3,1]], what is 2C (scalar multiplication)?", "options": ["[[8,4],[6,2]]", "[[6,4],[5,3]]", "[[8,2],[3,1]]", "[[4,2],[3,1]]"], "answer": 0, "exp": "Multiplying a matrix by a scalar means multiplying every element by that scalar: 2×[[4,2],[3,1]] = [[8,4],[6,2]].", "hint": "Multiply every single element of the matrix by the scalar."}, {"id": "srg112010", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Matrices — Identity Matrix", "difficulty": "hard", "style": "standard", "paper": "G11-G2", "q": "What is the 'identity matrix' for 2×2 matrices?", "options": ["[[1,0],[0,1]]", "[[0,1],[1,0]]", "[[1,1],[1,1]]", "[[0,0],[0,0]]"], "answer": 0, "exp": "The 2×2 identity matrix is [[1,0],[0,1]], which acts like the number 1 in matrix multiplication — multiplying any matrix by it leaves the matrix unchanged.", "hint": "Think about the matrix equivalent of multiplying a number by 1."}, {"id": "srg112011", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Matrices — Concepts", "difficulty": "hard", "style": "standard", "paper": "G11-G2", "q": "What is the order (dimensions) of the matrix [[1,2,3],[4,5,6]]?", "options": ["2×3 (2 rows, 3 columns)", "3×2 (3 rows, 2 columns)", "2×2", "6×1"], "answer": 0, "exp": "This matrix has 2 rows and 3 columns, so its order is written as 2×3 (rows × columns).", "hint": "Count the number of rows first, then the number of columns."}, {"id": "srg112012", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Matrices — Multiplication", "difficulty": "hard", "style": "standard", "paper": "G11-G2", "q": "For two matrices to be multiplied together (A × B), what condition must be satisfied regarding their dimensions?", "options": ["both matrices must have exactly the same dimensions", "the number of columns in A must equal the number of rows in B", "both matrices must be square", "there is no dimensional requirement for matrix multiplication"], "answer": 1, "exp": "For matrix multiplication A × B to be defined, the number of columns in A must equal the number of rows in B.", "hint": "Think about matching the 'inner' dimensions of the two matrices."}, {"id": "srg112013", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Matrices — Applications", "difficulty": "hard", "style": "standard", "paper": "G11-G2", "q": "A matrix A = [[2,3],[1,4]] is multiplied by the column vector v = [5,7]. What is A × v?", "options": ["[31,33]", "[10,21]", "[14,18]", "[29,32]"], "answer": 0, "exp": "Step 1: Top element = (2×5)+(3×7) = 10+21 = 31. Step 2: Bottom element = (1×5)+(4×7) = 5+28 = 33. Result: [31,33].", "hint": "Multiply each row of the matrix by the vector, summing the products."}, {"id": "srg112014", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Matrices — Transition Matrices", "difficulty": "hard", "style": "standard", "paper": "G11-G2", "q": "In a transition matrix used to model population movement between two regions each year, what does each column typically represent?", "options": ["the total population only", "the probabilities of moving FROM a particular region TO each other region", "a fixed dollar amount", "the names of each region"], "answer": 1, "exp": "In a transition matrix, each column typically represents the probabilities of moving FROM that region TO each other region (including staying in the same region), with columns usually summing to 1.", "hint": "Think about each column representing all the possible destinations from one particular starting point."}, {"id": "srg112015", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Matrices — Transition Matrices", "difficulty": "hard", "style": "standard", "paper": "G11-G2", "q": "A transition matrix T = [[0.8,0.3],[0.2,0.7]] represents yearly movement between City A and City B. If the initial population vector is [5000, 5000] (City A, City B), what is the population distribution after one year?", "options": ["[5000, 5000]", "[5500, 4500]", "[5800, 4200]", "[4500, 5500]"], "answer": 1, "exp": "Step 1: New City A = (0.8×5000)+(0.3×5000) = 4000+1500 = 5500. Step 2: New City B = (0.2×5000)+(0.7×5000) = 1000+3500 = 4500.", "hint": "Multiply the transition matrix by the population vector, following the matrix multiplication rules."}, {"id": "srg112016", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Matrices — Applications", "difficulty": "hard", "style": "standard", "paper": "G11-G2", "q": "Which best describes why matrices are useful for representing transformations, such as reflections or rotations, in coordinate geometry?", "options": ["matrices have no real connection to geometric transformations", "a matrix can be multiplied by a coordinate vector to systematically calculate the new, transformed coordinates", "matrices can only represent addition, not transformation", "transformations cannot be represented mathematically at all"], "answer": 1, "exp": "A transformation matrix can be multiplied by a coordinate vector to systematically calculate new, transformed coordinates, making matrices a powerful and consistent tool for representing geometric transformations like reflections and rotations.", "hint": "Think about how multiplying a matrix by a point's coordinates could systematically move that point."}, {"id": "srg112017", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Matrices — Transpose", "difficulty": "hard", "style": "standard", "paper": "G11-G2", "q": "What is the transpose of the matrix [[1,2,3],[4,5,6]]?", "options": ["[[1,4],[2,5],[3,6]]", "[[4,5,6],[1,2,3]]", "[[1,2,3],[4,5,6]]", "[[6,5,4],[3,2,1]]"], "answer": 0, "exp": "The transpose of a matrix swaps its rows and columns: the original 2×3 matrix becomes a 3×2 matrix, with the first row becoming the first column.", "hint": "Think about flipping the matrix so that rows become columns."}, {"id": "srg112018", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Matrices — Addition", "difficulty": "hard", "style": "standard", "paper": "G11-G2", "q": "Two matrices, both 3×3, are added together. What is the order (dimensions) of the resulting matrix?", "options": ["3×3", "6×6", "9×9", "3×6"], "answer": 0, "exp": "Adding two matrices of the same order results in a matrix of that same order — adding two 3×3 matrices gives another 3×3 matrix.", "hint": "Matrix addition does not change the dimensions of the resulting matrix."}, {"id": "srg112019", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Matrices — Addition", "difficulty": "hard", "style": "standard", "paper": "G11-G2", "q": "Which of these correctly describes when two matrices CANNOT be added together?", "options": ["they can always be added, regardless of their dimensions", "they cannot be added if they do not have exactly the same dimensions (same number of rows and columns)", "they cannot be added if they contain negative numbers", "they cannot be added if their determinant is zero"], "answer": 1, "exp": "Matrices can only be added together if they have exactly the same dimensions (the same number of rows and the same number of columns).", "hint": "Think about needing to match up every single element — what would happen if the matrices were different sizes?"}, {"id": "srg112020", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Matrices — Applications", "difficulty": "hard", "style": "standard", "paper": "G11-G2", "q": "A Leslie matrix is used to model an animal population's age groups over time. What kind of information does a Leslie matrix typically capture?", "options": ["only the total population size, with no further detail", "birth (fertility) rates and survival rates between different age groups", "the geographic location of the population only", "the matrix has no real biological application"], "answer": 1, "exp": "A Leslie matrix captures birth (fertility) rates for each age group and survival rates between consecutive age groups, allowing population structure to be projected forward over time.", "hint": "Think about the two key biological processes (births and survival) that determine how a population's age structure changes."}, {"id": "srg112021", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Matrices — Determinant", "difficulty": "hard", "style": "standard", "paper": "G11-G2", "q": "What is the determinant of the identity matrix [[1,0],[0,1]]?", "options": ["0", "1", "2", "-1"], "answer": 1, "exp": "The determinant of the identity matrix is always 1: (1×1) − (0×0) = 1.", "hint": "Apply the determinant formula ad − bc to the identity matrix."}, {"id": "srg112022", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Matrices — Inverse", "difficulty": "hard", "style": "standard", "paper": "G11-G2", "q": "Which best describes why the inverse of a matrix is useful for solving a matrix equation like AX = B (solving for X)?", "options": ["inverses have no real use in solving matrix equations", "multiplying both sides by A⁻¹ isolates X, similar to dividing both sides of a normal equation by a number", "inverses can only be used for addition, not solving equations", "matrix equations can never be solved using inverses"], "answer": 1, "exp": "Multiplying both sides of AX = B by A⁻¹ gives X = A⁻¹B, isolating X — this is the matrix equivalent of dividing both sides of a normal algebraic equation by a number to solve for an unknown.", "hint": "Think about how dividing both sides of a normal equation by a number isolates the unknown — matrix inverses work similarly."}, {"id": "srg112023", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Matrices — Determinant", "difficulty": "hard", "style": "standard", "paper": "G11-G2", "q": "A 2×2 matrix has a determinant of 0. What can be concluded about solving a matrix equation using this matrix?", "options": ["the equation can always be solved uniquely using the inverse", "the matrix has no inverse, so this method cannot be used to find a unique solution", "the determinant has no bearing on solving the equation", "the equation will always have infinite solutions regardless of the matrix"], "answer": 1, "exp": "Since a determinant of 0 means the matrix has no inverse, the standard method of multiplying by the inverse cannot be used to find a unique solution to the matrix equation.", "hint": "Think about what a zero determinant means for whether the matrix can be inverted."}, {"id": "srg112024", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Matrices — Transition Matrices", "difficulty": "hard", "style": "standard", "paper": "G11-G2", "q": "In a transition matrix, why must each column's probabilities sum to exactly 1?", "options": ["this is not actually a requirement for transition matrices", "each column represents all possible outcomes from one starting state, and these probabilities must account for every possibility (summing to 100%)", "columns should always sum to 0", "this only applies to matrices with exactly 2 rows"], "answer": 1, "exp": "Each column represents all possible outcomes (destinations) from one particular starting state, and since something must happen, these probabilities must account for every possibility, summing to exactly 1 (100%).", "hint": "Think about all the possible places something could end up from one starting point — together, these must cover every possibility."}, {"id": "srg112025", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Matrices — Determinant", "difficulty": "hard", "style": "standard", "paper": "G11-G2", "q": "Given matrix M = [[5,2],[3,1]], what is the value of M's determinant, and is M invertible?", "options": ["determinant = -1, yes invertible", "determinant = 0, not invertible", "determinant = 11, yes invertible", "determinant = -1, not invertible"], "answer": 0, "exp": "Step 1: determinant = (5×1) − (2×3) = 5 − 6 = -1. Step 2: Since the determinant is non-zero, M is invertible.", "hint": "Calculate the determinant using ad − bc, then recall that a non-zero determinant means the matrix is invertible."}, {"id": "srg113001", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Networks — Basic Concepts", "difficulty": "hard", "style": "standard", "paper": "G11-G3", "q": "In graph theory, what is the 'degree' of a vertex?", "options": ["the total number of vertices in the graph", "the number of edges connected to that vertex", "the shortest path from that vertex to any other", "the total weight of the graph"], "answer": 1, "exp": "The degree of a vertex is the number of edges directly connected to it.", "hint": "Think about counting the connections leading away from a single point."}, {"id": "srg113002", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Networks — Basic Concepts", "difficulty": "hard", "style": "standard", "paper": "G11-G3", "q": "A graph has 7 edges. What is the sum of the degrees of all its vertices?", "options": ["7", "10", "14", "21"], "answer": 2, "exp": "Step 1: Each edge contributes to the degree count of two vertices (one at each end). Step 2: Sum of degrees = 2 × number of edges = 2 × 7 = 14.", "hint": "Remember that each edge is counted at both of its endpoints."}, {"id": "srg113003", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Networks — Eulerian Paths", "difficulty": "hard", "style": "standard", "paper": "G11-G3", "q": "What condition must be met for a graph to have an 'Eulerian path' (a path that uses every edge exactly once)?", "options": ["the graph must have exactly 0 or exactly 2 vertices of odd degree", "every vertex must have an even degree only", "the graph must have no cycles at all", "the graph must be a tree"], "answer": 0, "exp": "A graph has an Eulerian path if it has exactly 0 vertices of odd degree (an Eulerian circuit) or exactly 2 vertices of odd degree (an Eulerian path between those two vertices).", "hint": "Think about the specific number of 'odd degree' vertices allowed for this type of path to exist."}, {"id": "srg113004", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Networks — Hamiltonian Paths", "difficulty": "hard", "style": "standard", "paper": "G11-G3", "q": "What is a 'Hamiltonian path' in a graph?", "options": ["a path that uses every edge exactly once", "a path that visits every vertex exactly once", "a path with the minimum total weight", "a path that returns to its starting vertex"], "answer": 1, "exp": "A Hamiltonian path visits every vertex in the graph exactly once (unlike an Eulerian path, which is concerned with edges, not vertices).", "hint": "Think about visiting every 'place' (vertex) once, rather than every 'connection' (edge)."}, {"id": "srg113005", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Networks — Graph Colouring", "difficulty": "hard", "style": "standard", "paper": "G11-G3", "q": "What is the minimum number of colours needed to colour a simple graph so that no two adjacent vertices share the same colour, if the graph contains a triangle (3 mutually connected vertices)?", "options": ["1", "2", "3", "4"], "answer": 2, "exp": "A triangle (3 vertices all connected to each other) requires at least 3 colours, since each vertex is adjacent to both of the other two, so no two can share a colour.", "hint": "Think about how many different colours are needed so that every pair of connected vertices in the triangle differs."}, {"id": "srg113006", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Networks — Shortest Path", "difficulty": "hard", "style": "standard", "paper": "G11-G3", "q": "A network has vertices A, B, C, D with direct connections: A-B (4), A-C (2), C-B (1), C-D (5), B-D (3), with numbers representing distances. What is the shortest path distance from A to D?", "options": ["6", "7", "8", "9"], "answer": 0, "exp": "Step 1: Path A-C-B-D: 2+1+3=6. Step 2: Path A-C-D: 2+5=7. Step 3: Path A-B-D: 4+3=7. Step 4: The shortest is A-C-B-D at a total distance of 6.", "hint": "Try all reasonable paths from A to D and compare their total distances."}, {"id": "srg113007", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Networks — Minimum Spanning Tree", "difficulty": "hard", "style": "standard", "paper": "G11-G3", "q": "What is a 'minimum spanning tree' of a connected, weighted graph?", "options": ["the tree that includes only the single shortest edge", "a subgraph connecting all vertices with the minimum possible total edge weight, with no cycles", "a graph with the maximum number of edges", "a path that visits every vertex exactly once"], "answer": 1, "exp": "A minimum spanning tree connects all vertices in a graph using the minimum possible total edge weight, while containing no cycles (forming a 'tree' structure).", "hint": "Think about connecting every point in a network as cheaply as possible, without creating any loops."}, {"id": "srg113008", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Networks — Minimum Spanning Tree", "difficulty": "hard", "style": "standard", "paper": "G11-G3", "q": "A network has 5 vertices. What is the minimum number of edges required for a spanning tree connecting all 5 vertices?", "options": ["3", "4", "5", "10"], "answer": 1, "exp": "A spanning tree connecting n vertices always requires exactly n−1 edges. For 5 vertices, this is 5−1=4 edges.", "hint": "Remember the rule: a spanning tree always has one fewer edge than the number of vertices."}, {"id": "srg113009", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Networks — Critical Path Analysis", "difficulty": "hard", "style": "standard", "paper": "G11-G3", "q": "In a project planning network (activity chart), what does the 'critical path' represent?", "options": ["the shortest possible path through the network", "the longest path through the network, determining the minimum time needed to complete the entire project", "a path that can be skipped without delaying the project", "a path with no connection to project duration"], "answer": 1, "exp": "The critical path is the LONGEST path through a project network, representing the minimum time required to complete the entire project — any delay on this path delays the whole project.", "hint": "Think carefully — for project planning, it's the longest path that matters, not the shortest."}, {"id": "srg113010", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Networks — Critical Path Analysis", "difficulty": "hard", "style": "standard", "paper": "G11-G3", "q": "In critical path analysis, what is 'float' (or 'slack') for a particular activity?", "options": ["the total duration of the entire project", "the amount of time an activity can be delayed without delaying the overall project completion", "the cost associated with an activity", "the number of workers assigned to an activity"], "answer": 1, "exp": "Float (or slack) is the amount of time a particular activity can be delayed without affecting the overall project completion time.", "hint": "Think about how much 'wiggle room' an activity has before it starts affecting the whole project's timeline."}, {"id": "srg113011", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Networks — Critical Path Analysis", "difficulty": "hard", "style": "standard", "paper": "G11-G3", "q": "What is the float of an activity that lies ON the critical path?", "options": ["always a large positive number", "always exactly zero", "always negative", "float does not apply to critical path activities"], "answer": 1, "exp": "Activities on the critical path always have zero float, since any delay to them directly delays the entire project.", "hint": "Think about why activities on the LONGEST path through the network have no room to be delayed."}, {"id": "srg113012", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Networks — Critical Path Analysis", "difficulty": "hard", "style": "standard", "paper": "G11-G3", "q": "A project has activities with the following durations along its critical path: 4 days, 7 days, 3 days, and 5 days. What is the minimum total project completion time?", "options": ["15 days", "17 days", "19 days", "21 days"], "answer": 2, "exp": "Step 1: Add the durations along the critical path: 4+7+3+5. Step 2: This gives 19 days.", "hint": "Add up all the activity durations that lie along the critical path."}, {"id": "srg113013", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Networks — Bipartite Graphs", "difficulty": "hard", "style": "standard", "paper": "G11-G3", "q": "What is a 'bipartite graph'?", "options": ["a graph with exactly two edges", "a graph whose vertices can be divided into two groups, with edges only connecting vertices from different groups (never within the same group)", "a graph with no edges at all", "a graph that has exactly two cycles"], "answer": 1, "exp": "A bipartite graph has its vertices divided into two distinct groups, with every edge connecting a vertex from one group to a vertex in the other group, never within the same group.", "hint": "Think about two separate groups, where connections only ever go between the groups, never within one."}, {"id": "srg113014", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Networks — Applications", "difficulty": "hard", "style": "standard", "paper": "G11-G3", "q": "Which real-world scenario would most likely be modelled using a bipartite graph?", "options": ["a road map showing distances between cities", "matching workers to specific jobs they are qualified for", "a family tree showing generations", "a map of friendships within one single school class"], "answer": 1, "exp": "Matching workers to jobs naturally forms two distinct groups (workers and jobs), with connections only made between a worker and a job (never between two workers or two jobs) — a classic bipartite scenario.", "hint": "Think about a situation with two genuinely separate, distinct categories being matched to each other."}, {"id": "srg113015", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Networks — Flow Problems", "difficulty": "hard", "style": "standard", "paper": "G11-G3", "q": "What is the 'capacity' of an edge in a flow network (such as a network of pipes or roads)?", "options": ["the total number of edges in the network", "the maximum amount of flow that can pass through that edge", "the shortest distance represented by that edge", "the number of vertices connected to that edge"], "answer": 1, "exp": "Capacity refers to the maximum amount of flow (such as water, traffic, or data) that can pass through a particular edge in a flow network.", "hint": "Think about the maximum amount that can travel along one specific connection."}, {"id": "srg113016", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Networks — Flow Problems", "difficulty": "hard", "style": "standard", "paper": "G11-G3", "q": "In a flow network, what does the 'maximum flow' from a source to a sink represent?", "options": ["the total number of edges in the network", "the greatest possible total flow that can be sent from the source to the sink, given the capacity constraints", "the shortest path between the source and sink", "the number of vertices between the source and sink"], "answer": 1, "exp": "Maximum flow represents the greatest possible total amount that can be sent from a source vertex to a sink vertex through the network, limited by the capacities of the edges along the way.", "hint": "Think about the largest possible total amount that can successfully get from the start to the end of the network."}, {"id": "srg113017", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Networks — Eulerian Paths", "difficulty": "hard", "style": "standard", "paper": "G11-G3", "q": "A simple graph has vertices with degrees 3, 3, 2, 2. Does this graph have an Eulerian path?", "options": ["yes, an Eulerian circuit, since all degrees are even", "yes, an Eulerian path (not a circuit), since exactly two vertices have odd degree", "no, since there are too many odd-degree vertices", "it is impossible to determine without more information"], "answer": 1, "exp": "This graph has exactly two vertices of odd degree (both with degree 3), which means it has an Eulerian path (though not a full circuit, since not all vertices have even degree).", "hint": "Count how many vertices have an odd degree, and recall the rule for Eulerian paths versus circuits."}, {"id": "srg113018", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Networks — Basic Concepts", "difficulty": "hard", "style": "standard", "paper": "G11-G3", "q": "What is the difference between a 'directed' graph and an 'undirected' graph?", "options": ["there is no real difference between them", "in a directed graph, edges have a specific direction (like one-way streets), while in an undirected graph, edges can be traversed in either direction", "directed graphs can never have cycles", "undirected graphs always have more vertices than directed graphs"], "answer": 1, "exp": "In a directed graph, each edge has a specific direction (similar to a one-way street), while in an undirected graph, edges can be traversed in either direction (like a two-way street).", "hint": "Think about the difference between a one-way street and a two-way street."}, {"id": "srg113019", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Networks — Shortest Path", "difficulty": "hard", "style": "standard", "paper": "G11-G3", "q": "Which algorithm is commonly used to find the shortest path between two vertices in a weighted graph?", "options": ["Dijkstra's algorithm", "the bubble sort algorithm", "linear regression", "the quadratic formula"], "answer": 0, "exp": "Dijkstra's algorithm is a commonly used method for finding the shortest path between vertices in a weighted graph.", "hint": "This algorithm is named after the computer scientist who developed it."}, {"id": "srg113020", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Networks — Applications", "difficulty": "hard", "style": "standard", "paper": "G11-G3", "q": "A scheduling problem assigns workers to tasks to minimise total completion time. What type of mathematical problem is this most likely classified as?", "options": ["a network flow problem only", "an allocation (assignment) problem, often solved using methods related to bipartite matching", "a problem with no real mathematical structure", "a simple addition problem"], "answer": 1, "exp": "This is an allocation (assignment) problem, often solved using methods related to bipartite matching, where workers and tasks form the two distinct groups being matched.", "hint": "Think about matching workers to tasks as forming two distinct groups needing to be paired up efficiently."}, {"id": "srg113021", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Networks — Critical Path Analysis", "difficulty": "hard", "style": "standard", "paper": "G11-G3", "q": "In a project network diagram, what does an 'activity' typically represent?", "options": ["a single point in time with no duration", "a task with a specific duration that must be completed as part of the project", "a type of vertex with no real-world meaning", "the total cost of the entire project"], "answer": 1, "exp": "An activity represents a task with a specific duration that must be completed as part of the overall project, often shown as an edge connecting two events (nodes) in the network diagram.", "hint": "Think about a specific job or task that takes some amount of time to complete."}, {"id": "srg113022", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Networks — Critical Path Analysis", "difficulty": "hard", "style": "standard", "paper": "G11-G3", "q": "If reducing the duration of a non-critical-path activity by 2 days, what effect would this most likely have on the overall project completion time?", "options": ["it would always reduce the total project time by exactly 2 days", "it would likely have no effect on the overall project completion time, since this activity is not on the critical path", "it would always increase the total project time", "it is impossible to determine the effect of any activity change"], "answer": 1, "exp": "Since the activity is not on the critical path, reducing its duration would likely have no effect on the overall project completion time, as the critical path (the longest path) still determines the minimum total duration.", "hint": "Think about whether shortening an activity NOT on the longest path through the network actually changes that longest path."}, {"id": "srg113023", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Networks — Critical Path Analysis", "difficulty": "hard", "style": "standard", "paper": "G11-G3", "q": "Why might project managers focus particular attention on activities along the critical path?", "options": ["critical path activities are always the cheapest to complete", "critical path activities have zero float, meaning any delay to them directly delays the entire project", "critical path activities are always optional", "critical path activities have no real significance"], "answer": 1, "exp": "Project managers focus on critical path activities because they have zero float — any delay to these specific activities directly delays the entire project's completion.", "hint": "Think about which activities have no room for delay, given their direct impact on the overall timeline."}, {"id": "srg113024", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Networks — Minimum Spanning Tree", "difficulty": "hard", "style": "standard", "paper": "G11-G3", "q": "A connected graph has 6 vertices and 8 edges. How many edges would need to be removed (without disconnecting the graph) to turn it into a spanning tree?", "options": ["2", "3", "5", "8"], "answer": 1, "exp": "Step 1: A spanning tree for 6 vertices needs 6−1=5 edges. Step 2: The graph currently has 8 edges, so 8−5=3 edges need to be removed.", "hint": "A spanning tree needs (number of vertices − 1) edges — find the difference between this and the current number of edges."}, {"id": "srg113025", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Networks — Eulerian Paths", "difficulty": "hard", "style": "standard", "paper": "G11-G3", "q": "A graph has vertices with degrees 4, 4, 4, 2. Does this graph have an Eulerian circuit (a closed path using every edge exactly once, returning to the start)?", "options": ["yes, since all vertices have even degree", "no, since not all vertices have the same degree", "yes, but only because the graph has exactly 4 vertices", "no, an Eulerian circuit is never possible in any graph"], "answer": 0, "exp": "An Eulerian circuit exists if and only if every vertex has an even degree (in a connected graph). Since all four degrees here (4, 4, 4, 2) are even, an Eulerian circuit exists.", "hint": "An Eulerian circuit requires every single vertex to have an even degree, not just some of them."}, {"id": "srg114001", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Data Analysis — Mean", "difficulty": "hard", "style": "standard", "paper": "G11-G4", "q": "Find the mean of this data set: 12, 15, 18, 9, 21, 14, 17, 11", "options": ["13.6", "14.0", "14.6", "15.0"], "answer": 2, "exp": "Step 1: Sum the values: 12+15+18+9+21+14+17+11=117. Step 2: Divide by 8: 117÷8=14.625, which rounds to 14.6.", "hint": "Add all values, then divide by how many values there are."}, {"id": "srg114002", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Data Analysis — Median", "difficulty": "hard", "style": "standard", "paper": "G11-G4", "q": "Find the median of this data set: 12, 15, 18, 9, 21, 14, 17, 11", "options": ["13.5", "14.5", "15.0", "15.5"], "answer": 1, "exp": "Step 1: Order the data: 9, 11, 12, 14, 15, 17, 18, 21. Step 2: With 8 values, the median is the average of the 4th and 5th values: (14+15)÷2=14.5.", "hint": "Order the data first, then find the middle value (or average of the two middle values for an even data set)."}, {"id": "srg114003", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Data Analysis — Standard Deviation", "difficulty": "hard", "style": "standard", "paper": "G11-G4", "q": "Find the standard deviation of this data set, to one decimal place: 12, 15, 18, 9, 21, 14, 17, 11 (using the sample standard deviation formula)", "options": ["3.0", "3.4", "4.0", "4.4"], "answer": 2, "exp": "Using the sample standard deviation formula (dividing by n−1), the standard deviation of this data set is approximately 4.0.", "hint": "Standard deviation measures the typical spread of data around the mean — use your calculator's statistical mode to compute this."}, {"id": "srg114004", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Data Analysis — Z-scores", "difficulty": "hard", "style": "standard", "paper": "G11-G4", "q": "A data set has a mean of 75 and a standard deviation of 5. What is the z-score for a value of 82?", "options": ["1.0", "1.2", "1.4", "1.6"], "answer": 2, "exp": "Step 1: z-score = (value − mean) ÷ standard deviation. Step 2: (82−75)÷5 = 1.4.", "hint": "Subtract the mean from the value, then divide by the standard deviation."}, {"id": "srg114005", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Probability — Expected Value", "difficulty": "hard", "style": "standard", "paper": "G11-G4", "q": "A discrete random variable X has the probability distribution: P(X=0)=0.1, P(X=1)=0.3, P(X=2)=0.4, P(X=3)=0.2. What is the expected value, E(X)?", "options": ["1.5", "1.7", "1.9", "2.0"], "answer": 1, "exp": "Step 1: E(X) = Σ(x × P(x)) = (0×0.1)+(1×0.3)+(2×0.4)+(3×0.2). Step 2: 0+0.3+0.8+0.6=1.7.", "hint": "Multiply each value by its probability, then add all the results together."}, {"id": "srg114006", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Probability — Discrete Random Variables", "difficulty": "hard", "style": "standard", "paper": "G11-G4", "q": "For a discrete random variable, what condition must the sum of all probabilities satisfy?", "options": ["the sum must equal 0", "the sum must equal exactly 1", "the sum must always be greater than 1", "there is no required sum"], "answer": 1, "exp": "For any valid probability distribution, the sum of all probabilities for every possible outcome must equal exactly 1 (representing 100% certainty that some outcome occurs).", "hint": "Think about the total certainty that one of the possible outcomes must occur."}, {"id": "srg114007", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Probability — Variance", "difficulty": "hard", "style": "standard", "paper": "G11-G4", "q": "For the random variable in question 5 (P(X=0)=0.1, P(X=1)=0.3, P(X=2)=0.4, P(X=3)=0.2, with E(X)=1.7), what is the variance, Var(X)?", "options": ["0.61", "0.81", "1.01", "1.21"], "answer": 1, "exp": "Step 1: Variance = Σ(P(x) × (x−E(X))²). Step 2: 0.1(0−1.7)²+0.3(1−1.7)²+0.4(2−1.7)²+0.2(3−1.7)² = 0.1(2.89)+0.3(0.49)+0.4(0.09)+0.2(1.69) = 0.289+0.147+0.036+0.338=0.81.", "hint": "Find the squared difference from the expected value for each outcome, weight by probability, then sum."}, {"id": "srg114008", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Data Analysis — Normal Distribution", "difficulty": "hard", "style": "standard", "paper": "G11-G4", "q": "Which best describes a 'normal distribution'?", "options": ["a distribution where all outcomes are equally likely", "a symmetric, bell-shaped distribution where most values cluster around the mean", "a distribution that only applies to discrete data", "a distribution with no defined mean"], "answer": 1, "exp": "A normal distribution is a symmetric, bell-shaped distribution where most values cluster around the mean, with frequency decreasing as you move further from the mean in either direction.", "hint": "Think about the classic 'bell curve' shape, symmetric around its centre."}, {"id": "srg114009", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Data Analysis — Normal Distribution", "difficulty": "hard", "style": "standard", "paper": "G11-G4", "q": "In a normal distribution, approximately what percentage of data falls within one standard deviation of the mean?", "options": ["50%", "68%", "95%", "99.7%"], "answer": 1, "exp": "In a normal distribution, approximately 68% of data falls within one standard deviation of the mean (part of the '68-95-99.7 rule').", "hint": "This is part of the commonly cited '68-95-99.7' rule for normal distributions."}, {"id": "srg114010", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Data Analysis — Normal Distribution", "difficulty": "hard", "style": "standard", "paper": "G11-G4", "q": "In a normal distribution, approximately what percentage of data falls within two standard deviations of the mean?", "options": ["68%", "85%", "95%", "99.7%"], "answer": 2, "exp": "In a normal distribution, approximately 95% of data falls within two standard deviations of the mean.", "hint": "This is the second value in the commonly cited '68-95-99.7' rule."}, {"id": "srg114011", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Data Analysis — IQR", "difficulty": "hard", "style": "standard", "paper": "G11-G4", "q": "Find the interquartile range (IQR) of this data set: 4, 8, 12, 15, 16, 19, 23, 42", "options": ["7", "9", "11", "38"], "answer": 1, "exp": "Step 1: Lower quartile (Q1) = 11, upper quartile (Q3) = 20 (using the standard quartile method on 8 ordered values). Step 2: IQR = Q3 − Q1 = 20 − 11 = 9.", "hint": "Find the lower and upper quartiles first, then subtract."}, {"id": "srg114012", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Data Analysis — Outliers", "difficulty": "hard", "style": "standard", "paper": "G11-G4", "q": "Using the data set 4, 8, 12, 15, 16, 19, 23, 42 and an IQR of 9 (Q1=11, Q3=20), which value would be classified as an outlier using the rule 'more than 1.5×IQR beyond Q1 or Q3'?", "options": ["8", "15", "19", "42"], "answer": 3, "exp": "Step 1: Upper outlier boundary = Q3 + 1.5×IQR = 20 + 13.5 = 33.5. Step 2: Since 42 exceeds this boundary, it is classified as an outlier.", "hint": "Calculate the upper boundary (Q3 + 1.5×IQR) and check which value exceeds it."}, {"id": "srg114013", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Data Analysis — Measures of Centre", "difficulty": "hard", "style": "standard", "paper": "G11-G4", "q": "Which measure of central tendency is most affected by extreme outliers in a data set?", "options": ["the median", "the mode", "the mean", "the range"], "answer": 2, "exp": "The mean is most affected by extreme outliers, since it takes the actual size of every value into account, unlike the median (based on position) or mode (based on frequency).", "hint": "Think about which measure depends on the actual SIZE of every value, rather than just its position or frequency."}, {"id": "srg114014", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Data Analysis — Distribution Shape", "difficulty": "hard", "style": "standard", "paper": "G11-G4", "q": "A box plot shows a data set with a long whisker extending to the right and a shorter whisker to the left, with the median closer to the left side of the box. What does this suggest about the data's distribution?", "options": ["the data is symmetric", "the data is positively skewed (skewed to the right)", "the data is negatively skewed (skewed to the left)", "no conclusion can be drawn from a box plot"], "answer": 1, "exp": "A longer right whisker and a median positioned toward the left of the box suggests the data is positively skewed (skewed to the right), with a tail of higher values extending further than the lower values.", "hint": "Think about the direction the longer 'tail' points — this indicates the direction of skew."}, {"id": "srg114015", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Data Analysis — Measures of Centre", "difficulty": "hard", "style": "standard", "paper": "G11-G4", "q": "Which best describes the 'mode' of a data set?", "options": ["the middle value when data is ordered", "the value that appears most frequently", "the average of all values", "the difference between the highest and lowest values"], "answer": 1, "exp": "The mode is the value that appears most frequently within a data set.", "hint": "Think about the most common, most frequently occurring value."}, {"id": "srg114016", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Probability — Expected Value", "difficulty": "hard", "style": "standard", "paper": "G11-G4", "q": "A fair six-sided die is rolled. Let X represent the value rolled. What is E(X), the expected value?", "options": ["3", "3.5", "4", "4.5"], "answer": 1, "exp": "Step 1: Each outcome (1-6) has probability 1/6. Step 2: E(X) = (1+2+3+4+5+6)/6 × ... actually: E(X) = Σ(x × 1/6) = (1+2+3+4+5+6)/6 = 21/6 = 3.5.", "hint": "With equal probabilities, the expected value is simply the average of all possible outcomes."}, {"id": "srg114017", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Data Analysis — Concepts", "difficulty": "hard", "style": "standard", "paper": "G11-G4", "q": "Which best describes the difference between a 'population' and a 'sample' in statistics?", "options": ["they mean exactly the same thing", "a population includes every member of a defined group, while a sample is a subset selected from that population", "a sample is always larger than the population", "populations are only relevant in biology, not statistics"], "answer": 1, "exp": "A population includes every member of a defined group being studied, while a sample is a smaller subset selected from that population, often used to make inferences about the whole population.", "hint": "Think about the difference between studying EVERYONE in a group versus just a smaller, representative portion."}, {"id": "srg114018", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Data Analysis — Concepts", "difficulty": "hard", "style": "standard", "paper": "G11-G4", "q": "Why might researchers use a sample rather than studying an entire population?", "options": ["samples are always less accurate, with no practical benefit", "studying an entire population can be impractical, time-consuming, or costly, making a well-chosen sample more feasible", "populations are never relevant to research", "sampling always produces identical results to studying the whole population"], "answer": 1, "exp": "Studying an entire population can be impractical, time-consuming, or costly, so researchers often use a well-chosen, representative sample instead, which can still provide useful and reasonably accurate insights.", "hint": "Think about the practical challenges of trying to survey or measure absolutely everyone in a large population."}, {"id": "srg114019", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Data Analysis — Z-scores", "difficulty": "hard", "style": "standard", "paper": "G11-G4", "q": "A test score of 88 has a z-score of 1.5, given the test has a standard deviation of 8. What is the mean test score?", "options": ["72", "76", "80", "82"], "answer": 1, "exp": "Step 1: z = (value − mean) ÷ SD, so 1.5 = (88 − mean) ÷ 8. Step 2: 1.5×8 = 12, so 88 − mean = 12, giving mean = 76.", "hint": "Rearrange the z-score formula to solve for the mean."}, {"id": "srg114020", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Data Analysis — Concepts", "difficulty": "hard", "style": "standard", "paper": "G11-G4", "q": "Which best describes 'bias' in the context of data collection?", "options": ["a perfectly random and representative sampling method", "a systematic error in how data is collected, which can distort results in a particular direction", "a type of standard deviation calculation", "a synonym for sample size"], "answer": 1, "exp": "Bias refers to a systematic error in how data is collected (such as a non-representative sample), which can distort results in a particular, often predictable direction.", "hint": "Think about a flaw in the data collection process that consistently skews results one way."}, {"id": "srg114021", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Data Analysis — Concepts", "difficulty": "hard", "style": "standard", "paper": "G11-G4", "q": "A survey only samples people leaving a gym to ask about exercise habits in the general population. What type of issue does this best illustrate?", "options": ["a perfectly representative sample", "sampling bias, since gym-goers are unlikely to represent the exercise habits of the general population", "an example of a controlled experiment", "an example of a normal distribution"], "answer": 1, "exp": "This illustrates sampling bias, since people leaving a gym are far more likely to exercise regularly than the general population, making this sample unrepresentative of the broader population being studied.", "hint": "Think about whether people at a gym are likely to represent the exercise habits of everyone in a population, including those who never exercise."}, {"id": "srg114022", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Probability — Discrete Random Variables", "difficulty": "hard", "style": "standard", "paper": "G11-G4", "q": "A discrete random variable Y has only two possible outcomes: success (probability p) or failure (probability 1−p). What is this type of distribution called?", "options": ["a normal distribution", "a Bernoulli distribution", "a continuous distribution", "a bivariate distribution"], "answer": 1, "exp": "A random variable with exactly two possible outcomes (success or failure) follows a Bernoulli distribution.", "hint": "This distribution is named after a mathematician and describes situations with exactly two possible outcomes."}, {"id": "srg114023", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Data Analysis — Range", "difficulty": "hard", "style": "standard", "paper": "G11-G4", "q": "Find the range of this data set: 4, 8, 12, 15, 16, 19, 23, 42", "options": ["19", "23", "35", "38"], "answer": 3, "exp": "Step 1: Range = highest value − lowest value. Step 2: 42 − 4 = 38.", "hint": "Subtract the smallest value from the largest value."}, {"id": "srg114024", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Data Analysis — Measures of Centre", "difficulty": "hard", "style": "standard", "paper": "G11-G4", "q": "Which best describes why the median is often preferred over the mean when describing house prices in a suburb, which often include some very expensive outliers?", "options": ["the median is always easier to calculate than the mean", "the median is not significantly affected by extreme outliers, providing a more typical, representative value than the mean in this case", "the median and mean are always identical for house price data", "the median cannot be calculated for this type of data"], "answer": 1, "exp": "Since the median is based on position rather than the actual size of every value, it is not significantly affected by extreme outliers (such as a few very expensive houses), making it a more typical, representative measure in this context.", "hint": "Think about how a few extremely expensive houses might distort the mean, but not the median, of house prices."}, {"id": "srg114025", "state": "AU", "section": "sr_genmaths", "grade": "11", "topic": "Data Analysis — Normal Distribution", "difficulty": "hard", "style": "standard", "paper": "G11-G4", "q": "A set of test scores is approximately normally distributed with a mean of 70 and a standard deviation of 6. Approximately what percentage of students scored between 64 and 76?", "options": ["50%", "68%", "95%", "99.7%"], "answer": 1, "exp": "Step 1: 64 and 76 are each exactly one standard deviation from the mean (70−6=64, 70+6=76). Step 2: Approximately 68% of data falls within one standard deviation of the mean in a normal distribution.", "hint": "Check how many standard deviations away from the mean these two values are."}, {"id": "srg121001", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Recursion — Arithmetic Sequences", "difficulty": "hard", "style": "standard", "paper": "G12-G1", "q": "A sequence is defined by the recurrence relation u₁=5, uₙ₊₁=uₙ+3. What is u₄?", "options": ["11", "14", "17", "20"], "answer": 1, "exp": "Step 1: u₁=5, u₂=5+3=8, u₃=8+3=11. Step 2: u₄=11+3=14.", "hint": "Apply the recurrence rule repeatedly, starting from u₁, until you reach u₄."}, {"id": "srg121002", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Recursion — Geometric Sequences", "difficulty": "hard", "style": "standard", "paper": "G12-G1", "q": "A sequence is defined by u₁=2, uₙ₊₁=3×uₙ. What is u₅?", "options": ["54", "162", "486", "1458"], "answer": 1, "exp": "Step 1: u₁=2, u₂=6, u₃=18, u₄=54. Step 2: u₅=54×3=162.", "hint": "Apply the recurrence rule repeatedly, multiplying by 3 each time, starting from u₁."}, {"id": "srg121003", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Recursion — Financial Modelling", "difficulty": "hard", "style": "standard", "paper": "G12-G1", "q": "Which recurrence relation correctly models a loan of $10,000 with monthly interest of 1% and a fixed monthly repayment of $500, where Vₙ is the balance after n months?", "options": ["Vₙ₊₁ = Vₙ + 0.01 − 500", "Vₙ₊₁ = Vₙ × 1.01 − 500", "Vₙ₊₁ = Vₙ × 0.99 + 500", "Vₙ₊₁ = Vₙ − 500 × 1.01"], "answer": 1, "exp": "Each month, the balance grows by 1% interest (×1.01), then the repayment ($500) is subtracted: Vₙ₊₁ = Vₙ × 1.01 − 500.", "hint": "First apply the interest as a multiplication, then subtract the repayment."}, {"id": "srg121004", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Recursion — Financial Modelling", "difficulty": "hard", "style": "standard", "paper": "G12-G1", "q": "Using the loan recurrence Vₙ₊₁ = Vₙ × 1.01 − 500, with V₀ = $10,000, what is the balance after 2 months (V₂), to the nearest cent?", "options": ["$9100.00", "$9196.00", "$9296.00", "$9500.00"], "answer": 1, "exp": "Step 1: V₁ = 10000×1.01−500 = 9600. Step 2: V₂ = 9600×1.01−500 = 9696−500 = 9196.", "hint": "Apply the recurrence relation twice, starting from V₀."}, {"id": "srg121005", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Recursion — Depreciation", "difficulty": "hard", "style": "standard", "paper": "G12-G1", "q": "A car worth $20,000 depreciates by 10% of its value each year, modelled by Vₙ₊₁ = Vₙ × 0.9. What is its value after 3 years (V₃)?", "options": ["$14,000", "$14,580", "$16,200", "$18,000"], "answer": 1, "exp": "Step 1: V₁=20000×0.9=18000. Step 2: V₂=18000×0.9=16200. Step 3: V₃=16200×0.9=14580.", "hint": "Apply the recurrence relation three times, starting from the initial value."}, {"id": "srg121006", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Recursion — Annuities", "difficulty": "hard", "style": "standard", "paper": "G12-G1", "q": "An annuity recurrence is modelled by Aₙ₊₁ = Aₙ × 1.05 + 2000, with A₀ = 0 (regular deposits of $2000 at 5% interest per period). What is A₃, the balance after 3 deposits?", "options": ["$6000.00", "$6105.00", "$6305.00", "$6605.00"], "answer": 2, "exp": "Step 1: A₁=0×1.05+2000=2000. Step 2: A₂=2000×1.05+2000=4100. Step 3: A₃=4100×1.05+2000=6305.", "hint": "Apply the recurrence relation three times, starting from A₀=0."}, {"id": "srg121007", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Recursion — Concepts", "difficulty": "hard", "style": "standard", "paper": "G12-G1", "q": "Which best describes the difference between a recurrence relation and an explicit (closed-form) rule for a sequence?", "options": ["they are exactly the same thing", "a recurrence relation defines each term based on previous term(s), while an explicit rule calculates any term directly from its position number", "an explicit rule can only be used for arithmetic sequences", "a recurrence relation cannot be used to model financial situations"], "answer": 1, "exp": "A recurrence relation defines each term based on one or more previous terms, while an explicit rule allows you to calculate any term directly, using only its position number (n), without needing to know previous terms.", "hint": "Think about whether you need to know the PREVIOUS term to find the next one, or whether you can jump straight to any term using its position."}, {"id": "srg121008", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Recursion — Arithmetic Sequences", "difficulty": "hard", "style": "standard", "paper": "G12-G1", "q": "For the arithmetic sequence with u₁=5 and common difference d=3, what is the explicit rule for uₙ?", "options": ["uₙ = 5 + 3n", "uₙ = 5 + 3(n−1)", "uₙ = 3 + 5(n−1)", "uₙ = 5n + 3"], "answer": 1, "exp": "The explicit rule for an arithmetic sequence is uₙ = u₁ + d(n−1) = 5 + 3(n−1).", "hint": "Use the standard explicit formula for an arithmetic sequence: first term plus (n−1) times the common difference."}, {"id": "srg121009", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Recursion — Arithmetic Sequences", "difficulty": "hard", "style": "standard", "paper": "G12-G1", "q": "Using the explicit rule uₙ = 5 + 3(n−1), what is u₁₀?", "options": ["32", "35", "38", "41"], "answer": 0, "exp": "Step 1: Substitute n=10: u₁₀ = 5 + 3(10−1). Step 2: 5 + 3(9) = 5 + 27 = 32.", "hint": "Substitute n=10 into the explicit formula and calculate carefully."}, {"id": "srg121010", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Recursion — Geometric Sequences", "difficulty": "hard", "style": "standard", "paper": "G12-G1", "q": "For a geometric sequence with first term 2 and common ratio 3, what is the explicit rule for uₙ?", "options": ["uₙ = 2 × 3ⁿ", "uₙ = 2 × 3ⁿ⁻¹", "uₙ = 2ⁿ × 3", "uₙ = 3 × 2ⁿ⁻¹"], "answer": 1, "exp": "The explicit rule for a geometric sequence is uₙ = u₁ × rⁿ⁻¹ = 2 × 3ⁿ⁻¹.", "hint": "Use the standard explicit formula for a geometric sequence: first term times the ratio raised to the power of (n−1)."}, {"id": "srg121011", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Recursion — Financial Modelling", "difficulty": "hard", "style": "standard", "paper": "G12-G1", "q": "Which type of recurrence relation would best model a fixed-rate home loan with regular repayments, where Vₙ represents the balance owing after n repayment periods?", "options": ["a simple arithmetic recurrence (Vₙ₊₁ = Vₙ + d)", "a simple geometric recurrence (Vₙ₊₁ = r × Vₙ) with no subtraction", "a combined recurrence involving both multiplication (for interest) and subtraction (for repayments)", "recurrence relations cannot model loans"], "answer": 2, "exp": "A loan with regular repayments requires a combined recurrence relation, multiplying the balance by a growth factor for interest, then subtracting the repayment amount each period.", "hint": "Think about the TWO things happening to the loan balance each period: interest is added, and a repayment is subtracted."}, {"id": "srg121012", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Recursion — Financial Modelling", "difficulty": "hard", "style": "standard", "paper": "G12-G1", "q": "A $15,000 loan at 6% per annum (0.5% per month) is repaid with fixed monthly repayments of $300, modelled by Vₙ₊₁ = Vₙ × 1.005 − 300. What is the balance after 2 months (V₂), to the nearest cent?", "options": ["$14,400.00", "$14,548.87", "$14,775.00", "$14,850.75"], "answer": 1, "exp": "Step 1: V₁ = 15000×1.005−300 = $14,775.00. Step 2: V₂ = 14775×1.005−300 = $14,548.87.", "hint": "Apply the recurrence relation twice, starting from V₀=15000."}, {"id": "srg121013", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Recursion — Population Growth", "difficulty": "hard", "style": "standard", "paper": "G12-G1", "q": "A population of rabbits grows according to the recurrence Pₙ₊₁ = Pₙ × 1.2, with P₀ = 50. What is the population after 4 breeding cycles (P₄), to the nearest whole rabbit?", "options": ["86", "104", "104.4", "125"], "answer": 1, "exp": "Step 1: P₁=60, P₂=72, P₃=86.4. Step 2: P₄=86.4×1.2=103.68, which rounds to 104.", "hint": "Apply the recurrence relation four times, starting from P₀=50, then round at the end."}, {"id": "srg121014", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Recursion — Concepts", "difficulty": "hard", "style": "standard", "paper": "G12-G1", "q": "Which best describes a 'fixed point' or 'steady state' of a recurrence relation, such as one modelling a loan balance?", "options": ["a value that, once reached, would remain unchanged under the recurrence relation", "the very first term of the sequence", "the term where a sequence becomes negative", "a concept that never applies to financial recurrence relations"], "answer": 0, "exp": "A fixed point (or steady state) is a value that, if reached, would remain unchanged when the recurrence relation is applied again — useful for understanding long-term behaviour of a model.", "hint": "Think about a balance value where applying the recurrence relation again wouldn't actually change anything."}, {"id": "srg121015", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Recursion — Financial Modelling", "difficulty": "hard", "style": "standard", "paper": "G12-G1", "q": "For a loan being paid off (where repayments exceed the interest charged each period), what generally happens to the balance over time, according to the recurrence model?", "options": ["the balance increases without bound", "the balance decreases over time, eventually reaching zero", "the balance remains exactly constant", "the balance increases then decreases randomly"], "answer": 1, "exp": "When repayments exceed the interest charged each period, the loan balance decreases over time, eventually reaching zero as the loan is fully paid off.", "hint": "Think about what happens to a loan over time if you're paying off more than just the interest each period."}, {"id": "srg121016", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Recursion — Concepts", "difficulty": "hard", "style": "standard", "paper": "G12-G1", "q": "A car is purchased for $30,000 and depreciates by a flat $3000 per year, modelled by Vₙ₊₁ = Vₙ − 3000. What type of recurrence relation is this?", "options": ["a geometric recurrence", "an arithmetic recurrence", "an exponential recurrence with growth", "this is not a valid recurrence relation"], "answer": 1, "exp": "This is an arithmetic recurrence relation, since the same fixed amount ($3000) is subtracted each time, rather than multiplied by a ratio.", "hint": "Think about whether a fixed AMOUNT is being added/subtracted (arithmetic) or a fixed RATIO is being applied (geometric)."}, {"id": "srg121017", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Recursion — Depreciation", "difficulty": "hard", "style": "standard", "paper": "G12-G1", "q": "Using the recurrence Vₙ₊₁ = Vₙ − 3000 with V₀ = $30,000, after how many years will the car's value reach exactly $0?", "options": ["8 years", "9 years", "10 years", "12 years"], "answer": 2, "exp": "Step 1: Each year, the value decreases by $3000. Step 2: $30,000 ÷ $3000 = 10 years to reach $0.", "hint": "Divide the total value by the fixed amount lost each year."}, {"id": "srg121018", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Recursion — Technology", "difficulty": "hard", "style": "standard", "paper": "G12-G1", "q": "Which best describes how a spreadsheet can be used to model a recurrence relation over many time periods?", "options": ["spreadsheets cannot be used to model recurrence relations", "a formula can be entered once and then 'filled down' through successive rows, with each row referring back to the value in the row above", "spreadsheets can only calculate explicit (closed-form) rules, not recurrence relations", "recurrence relations require specialised software unavailable in standard spreadsheets"], "answer": 1, "exp": "A spreadsheet formula can be entered once, referencing the cell above it (the previous term), and then 'filled down' to automatically calculate many successive terms of a recurrence relation.", "hint": "Think about how a spreadsheet formula referring to 'the cell above' can be copied down through many rows."}, {"id": "srg121019", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Recursion — Financial Modelling", "difficulty": "hard", "style": "standard", "paper": "G12-G1", "q": "A perpetuity pays a fixed amount forever, with the balance modelled by Aₙ₊₁ = Aₙ × (1+r) − d, where the balance remains exactly constant over time (Aₙ₊₁ = Aₙ = A). Which equation correctly represents this steady-state condition?", "options": ["A = A × (1+r) − d, which simplifies to d = A × r", "A = A + r − d", "A = d × r", "A = A − d + r, with no further simplification possible"], "answer": 0, "exp": "If the balance A remains exactly constant, then A = A×(1+r) − d. Rearranging: A×r = d, meaning the regular payment (d) exactly equals the interest earned on the balance (A×r) each period.", "hint": "Set Aₙ₊₁ equal to Aₙ in the recurrence relation, then simplify algebraically."}, {"id": "srg121020", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Recursion — Financial Modelling", "difficulty": "hard", "style": "standard", "paper": "G12-G1", "q": "For the perpetuity steady-state condition d = A × r, if a perpetuity balance is $200,000 and the interest rate per period is 4% (0.04), what regular payment (d) can be sustained forever?", "options": ["$4,000", "$8,000", "$20,000", "$40,000"], "answer": 1, "exp": "Step 1: d = A × r. Step 2: d = 200,000 × 0.04 = $8,000.", "hint": "Multiply the balance by the interest rate per period."}, {"id": "srg121021", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Recursion — Concepts", "difficulty": "hard", "style": "standard", "paper": "G12-G1", "q": "Which of these is an example of a second-order recurrence relation, where a term depends on the TWO previous terms (rather than just one)?", "options": ["uₙ₊₁ = uₙ + 5", "uₙ₊₁ = 3 × uₙ", "uₙ₊₂ = uₙ₊₁ + uₙ", "uₙ = 2n + 1"], "answer": 2, "exp": "\"uₙ₊₂ = uₙ₊₁ + uₙ\" is a second-order recurrence relation, since each term depends on the two previous terms (this is actually the rule for the Fibonacci sequence).", "hint": "Look for the relation where a term depends on TWO earlier terms, not just one."}, {"id": "srg121022", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Recursion — Special Sequences", "difficulty": "hard", "style": "standard", "paper": "G12-G1", "q": "The Fibonacci sequence is defined by u₁=1, u₂=1, uₙ₊₂=uₙ₊₁+uₙ. What is u₆?", "options": ["5", "8", "13", "21"], "answer": 1, "exp": "Step 1: u₁=1, u₂=1, u₃=2, u₄=3, u₅=5. Step 2: u₆=u₅+u₄=5+3=8.", "hint": "Build up the sequence term by term, adding the two previous terms each time."}, {"id": "srg121023", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Recursion — Financial Modelling", "difficulty": "hard", "style": "standard", "paper": "G12-G1", "q": "Which best explains why understanding the LONG-TERM behaviour of a recurrence relation (such as whether a loan balance eventually reaches zero, or grows indefinitely) is useful in financial modelling?", "options": ["long-term behaviour has no practical financial relevance", "it helps determine whether a financial plan (such as a loan repayment schedule or investment strategy) will actually achieve its intended outcome over time", "recurrence relations can only ever be used for very short time periods", "long-term behaviour is identical for every recurrence relation"], "answer": 1, "exp": "Understanding long-term behaviour helps determine whether a financial plan, such as a loan repayment schedule, will actually pay off the loan in a reasonable time, or whether an investment strategy will grow as intended.", "hint": "Think about why a bank or financial planner would want to know what happens to a balance over many years, not just the first few periods."}, {"id": "srg121024", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Recursion — Financial Modelling", "difficulty": "hard", "style": "standard", "paper": "G12-G1", "q": "A savings account recurrence is given by Aₙ₊₁ = Aₙ × 1.03 + 100, with A₀ = 500. What is A₂, to the nearest cent?", "options": ["$715.00", "$724.55", "$733.45", "$745.00"], "answer": 2, "exp": "Step 1: A₁ = 500×1.03+100 = $615.00. Step 2: A₂ = 615×1.03+100 = $733.45.", "hint": "Apply the recurrence relation twice, starting from A₀=500."}, {"id": "srg121025", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Recursion — Financial Modelling", "difficulty": "hard", "style": "standard", "paper": "G12-G1", "q": "A loan recurrence Vₙ₊₁ = Vₙ × 1.008 − 450 models monthly repayments. If the FIRST repayment exactly equals the interest charged in that first month, what does this tell you about the loan balance after one month?", "options": ["the balance would increase", "the balance would decrease significantly", "the balance would remain exactly the same as the original amount", "the loan would be immediately paid off"], "answer": 2, "exp": "If the repayment exactly equals the interest charged, the balance after one month equals the original balance — none of the principal has been reduced yet, since the entire repayment only covered the interest.", "hint": "Think about what's left over to reduce the principal if the repayment only just covers the interest charged."}, {"id": "srg122001", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Matrices — Transition States", "difficulty": "hard", "style": "standard", "paper": "G12-G2", "q": "A transition matrix T = [[0.7,0.4],[0.3,0.6]] represents yearly movement between two regions. If the initial population vector is [1000, 2000], what is the population vector after 1 year?", "options": ["[1200, 1800]", "[1500, 1500]", "[1650, 1350]", "[1700, 1300]"], "answer": 1, "exp": "Step 1: Multiply T by the population vector: [0.7×1000+0.4×2000, 0.3×1000+0.6×2000]. Step 2: [700+800, 300+1200] = [1500, 1500].", "hint": "Multiply the transition matrix by the population vector, row by row."}, {"id": "srg122002", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Matrices — Transition States", "difficulty": "hard", "style": "standard", "paper": "G12-G2", "q": "Using the same transition matrix T = [[0.7,0.4],[0.3,0.6]] and initial vector [1000, 2000], what is the population vector after 2 years?", "options": ["[1500, 1500]", "[1650, 1350]", "[1700, 1300]", "[1800, 1200]"], "answer": 1, "exp": "Step 1: After 1 year, the population vector is [1500, 1500] (from the previous question). Step 2: Apply T again: [0.7×1500+0.4×1500, 0.3×1500+0.6×1500] = [1650, 1350].", "hint": "Apply the transition matrix to the result from the previous year, not the original starting vector."}, {"id": "srg122003", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Matrices — Transition States", "difficulty": "hard", "style": "standard", "paper": "G12-G2", "q": "What does T² (T multiplied by itself) represent, in the context of a transition matrix modelling yearly change?", "options": ["the transition over half a year", "the transition over exactly 2 years", "the transition matrix is squared for no particular reason", "T² has no meaningful interpretation"], "answer": 1, "exp": "T² represents the combined transition over 2 time periods (2 years), since applying the matrix twice models two successive years of change.", "hint": "Think about what happens if you apply the same one-year transition matrix twice in a row."}, {"id": "srg122004", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Matrices — Transition States", "difficulty": "hard", "style": "standard", "paper": "G12-G2", "q": "In a long-term transition matrix model, what is a 'steady state' (or equilibrium state)?", "options": ["a population distribution that changes dramatically every period", "a population distribution that, once reached, remains unchanged when the transition matrix is applied again", "the very first population distribution recorded", "a state that only applies to populations with exactly two categories"], "answer": 1, "exp": "A steady state is a population distribution that, once reached, remains unchanged (or proportionally unchanged) when the transition matrix is applied again — the system has reached long-term equilibrium.", "hint": "Think about a population split that, once reached, doesn't change any further over time."}, {"id": "srg122005", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Matrices — Leslie Matrices", "difficulty": "hard", "style": "standard", "paper": "G12-G2", "q": "In a Leslie matrix used to model an age-structured population, what do the values in the FIRST row typically represent?", "options": ["survival rates between age groups", "fertility (birth) rates for each age group", "the total population size", "the matrix's determinant"], "answer": 1, "exp": "The first row of a Leslie matrix typically contains fertility rates, representing the number of offspring produced by each age group.", "hint": "Think about which row would need to capture how many NEW individuals each age group contributes to the population."}, {"id": "srg122006", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Matrices — Leslie Matrices", "difficulty": "hard", "style": "standard", "paper": "G12-G2", "q": "In a Leslie matrix, what do the values in the sub-diagonal (just below the main diagonal) typically represent?", "options": ["fertility rates", "survival rates — the proportion of each age group that survives into the next age group", "the total population", "the matrix's inverse"], "answer": 1, "exp": "The sub-diagonal values in a Leslie matrix typically represent survival rates — the proportion of individuals in one age group that survive to become part of the next age group.", "hint": "Think about the proportion of a younger age group that 'survives' to become part of an older age group."}, {"id": "srg122007", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Matrices — Leslie Matrices", "difficulty": "hard", "style": "standard", "paper": "G12-G2", "q": "A Leslie matrix L = [[0,2,1],[0.5,0,0],[0,0.6,0]] is applied to an age-structured population vector [100, 80, 60] (young, middle, old). What is the population vector after one time period?", "options": ["[180, 50, 48]", "[220, 50, 48]", "[220, 60, 48]", "[180, 60, 50]"], "answer": 1, "exp": "Step 1: New young = 0×100+2×80+1×60 = 220. Step 2: New middle = 0.5×100+0×80+0×60 = 50. Step 3: New old = 0×100+0.6×80+0×60 = 48. Result: [220, 50, 48].", "hint": "Multiply the Leslie matrix by the population vector, calculating each row's result separately."}, {"id": "srg122008", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Matrices — Leslie Matrices", "difficulty": "hard", "style": "standard", "paper": "G12-G2", "q": "Why must the entries representing survival rates in a Leslie matrix always be between 0 and 1?", "options": ["there is no such restriction on these values", "a survival rate represents a proportion of a population, which logically cannot be negative or exceed 100% (1.0)", "survival rates can be any real number, including negative values", "survival rates must always equal exactly 1"], "answer": 1, "exp": "A survival rate represents the proportion of a population that survives into the next age group, which logically must be between 0 (none survive) and 1 (all survive) — it cannot be negative or exceed 100%.", "hint": "Think about what a 'proportion surviving' can logically range between."}, {"id": "srg122009", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Matrices — Leslie Matrices", "difficulty": "hard", "style": "standard", "paper": "G12-G2", "q": "What is the order (dimensions) of a Leslie matrix used to model a population divided into 4 age groups?", "options": ["3×3", "4×4", "4×3", "3×4"], "answer": 1, "exp": "A Leslie matrix modelling a population with 4 age groups must be a 4×4 square matrix, to correctly multiply with a 4-element population vector.", "hint": "The matrix must be square, with dimensions matching the number of age groups."}, {"id": "srg122010", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Matrices — Transition States", "difficulty": "hard", "style": "standard", "paper": "G12-G2", "q": "In a two-state transition matrix where every column sums to exactly 1, what does this property guarantee about the total population over time (assuming no births or deaths, only movement)?", "options": ["the total population will always double each period", "the total population remains constant, since the matrix only redistributes existing individuals between states", "the total population will shrink to zero eventually", "this property has no effect on the total population"], "answer": 1, "exp": "When every column of a transition matrix sums to exactly 1, the matrix only redistributes existing individuals between states (with no overall gain or loss), so the total population remains constant over time.", "hint": "Think about whether individuals are being created or destroyed by the matrix, or simply moved between categories."}, {"id": "srg122011", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Matrices — Transition States", "difficulty": "hard", "style": "standard", "paper": "G12-G2", "q": "Given the transition matrix T = [[0.7,0.4],[0.3,0.6]], which eigenvalue of T corresponds to the long-term steady-state behaviour of the system?", "options": ["0.3", "0.6", "0.7", "1"], "answer": 3, "exp": "For a transition matrix where columns sum to 1, the eigenvalue equal to 1 corresponds to the steady-state behaviour, with its associated eigenvector describing the long-term proportional distribution.", "hint": "For this type of transition matrix, look for the eigenvalue that always equals exactly 1."}, {"id": "srg122012", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Matrices — Transition States", "difficulty": "hard", "style": "standard", "paper": "G12-G2", "q": "Which best describes how matrix powers (such as T¹⁰) can be used to predict long-term behaviour in a transition matrix model?", "options": ["matrix powers cannot be used for this purpose", "calculating Tⁿ and applying it to an initial population vector predicts the population distribution after n time periods, useful for forecasting", "matrix powers only work for 1×1 matrices", "Tⁿ always equals T regardless of n"], "answer": 1, "exp": "Calculating Tⁿ and applying it to an initial population vector predicts the population distribution after n time periods, which is useful for forecasting long-term trends in a modelled system.", "hint": "Think about applying the same yearly transition repeatedly to project further into the future."}, {"id": "srg122013", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Matrices — Leslie Matrices", "difficulty": "hard", "style": "standard", "paper": "G12-G2", "q": "In a Leslie matrix model, if all fertility and survival rates remain constant over time, what type of long-term growth pattern does the total population eventually tend toward?", "options": ["the population always declines to zero, regardless of the rates", "exponential growth (or decline) at a rate determined by the matrix's dominant eigenvalue", "the population always grows linearly", "the population total has no predictable long-term pattern at all"], "answer": 1, "exp": "With constant fertility and survival rates, a Leslie matrix model's total population eventually tends toward exponential growth (or decline), with the rate determined by the matrix's dominant eigenvalue.", "hint": "Think about the type of growth pattern associated with repeated multiplication by a constant factor."}, {"id": "srg122014", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Matrices — Transition States", "difficulty": "hard", "style": "standard", "paper": "G12-G2", "q": "A 2×2 transition matrix has columns that sum to 1. If column 1 is [0.9, 0.1], what does the value 0.1 most likely represent?", "options": ["10% of state 1 remains in state 1 each period", "10% of state 1 moves to state 2 each period", "10% of state 2 moves to state 1 each period", "this value has no meaningful interpretation"], "answer": 1, "exp": "In column 1 (representing transitions FROM state 1), the value 0.1 in the second row represents the proportion of state 1 that moves TO state 2 each period.", "hint": "Remember that columns typically represent transitions FROM a particular state."}, {"id": "srg122015", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Matrices — Leslie Matrices", "difficulty": "hard", "style": "standard", "paper": "G12-G2", "q": "Which best explains why Leslie matrices are particularly useful for modelling wildlife populations, compared to a simple single growth rate?", "options": ["Leslie matrices have no real advantage over a single growth rate", "Leslie matrices account for different fertility and survival rates across different age groups, providing a more realistic and detailed population model", "Leslie matrices only work for populations with a single age group", "a single growth rate is always more accurate than a Leslie matrix"], "answer": 1, "exp": "Leslie matrices account for different fertility and survival rates across different age groups (since, for example, very young or very old individuals often reproduce less), providing a more realistic and detailed model than a single overall growth rate.", "hint": "Think about how reproduction and survival rates often differ significantly between very young, middle-aged, and elderly members of a population."}, {"id": "srg122016", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Matrices — Transition States", "difficulty": "hard", "style": "standard", "paper": "G12-G2", "q": "A transition matrix is applied repeatedly to model the long-term market share of two competing companies. After many periods, the market share vector stops changing significantly. What does this indicate?", "options": ["the model has failed completely", "the system has reached (or is very close to) a steady state", "one company has captured 100% of the market", "the transition matrix must have been entered incorrectly"], "answer": 1, "exp": "When the market share vector stops changing significantly after repeated application of the transition matrix, this indicates the system has reached (or is very close to) a long-term steady state.", "hint": "Think about what it means for a repeatedly-applied process to stop producing noticeable further change."}, {"id": "srg122017", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Matrices — Leslie Matrices", "difficulty": "hard", "style": "standard", "paper": "G12-G2", "q": "In a Leslie matrix [[0,2,1],[0.5,0,0],[0,0.6,0]] applied to population [100, 80, 60], the result was [220, 50, 48] after one period. Applying the matrix again to [220, 50, 48], what is the new young age group value?", "options": ["100", "148", "160", "200"], "answer": 1, "exp": "Step 1: New young = 0×220 + 2×50 + 1×48. Step 2: 0 + 100 + 48 = 148.", "hint": "Use the first row of the Leslie matrix (fertility rates) applied to the new population vector."}, {"id": "srg122018", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Matrices — Leslie Matrices", "difficulty": "hard", "style": "standard", "paper": "G12-G2", "q": "Which best describes why a 3×3 Leslie matrix would not be appropriate for modelling a population currently divided into 5 age groups?", "options": ["a 3×3 matrix can be used for any number of age groups without issue", "matrix dimensions must match the number of categories being modelled — a 5-age-group population requires a 5×5 Leslie matrix", "Leslie matrices are never restricted by size", "a 3×3 matrix would simply ignore the extra age groups with no other consequence"], "answer": 1, "exp": "Matrix dimensions must match the number of categories being modelled — to correctly multiply with a 5-element population vector (representing 5 age groups), a 5×5 Leslie matrix is required.", "hint": "Think about whether matrix multiplication is even possible if the matrix dimensions don't match the population vector's size."}, {"id": "srg122019", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Matrices — Transition States", "difficulty": "hard", "style": "standard", "paper": "G12-G2", "q": "Which best describes the typical structure of the entries in a transition matrix where rows (not columns) represent the destination state?", "options": ["this convention does not exist and is never used", "some textbooks use rows to represent the destination state instead of columns — both conventions exist, so it's important to check which is being used", "transition matrices can only ever use columns for destination states", "rows and columns always represent exactly the same information"], "answer": 1, "exp": "Both conventions exist in different textbooks and contexts — some use columns to represent the destination state, others use rows — so it's important to check which convention is being used in a specific problem.", "hint": "Think about why it's important to carefully check which convention (rows or columns as destination) is being used in any given problem."}, {"id": "srg122020", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Matrices — Transition States", "difficulty": "hard", "style": "standard", "paper": "G12-G2", "q": "A population's distribution is given by the vector [0.6, 0.4] (60% in state A, 40% in state B). After applying a transition matrix, the result is [0.6, 0.4] again, unchanged. What can be concluded?", "options": ["the transition matrix made an error", "this vector represents the system's steady state", "the population must be exactly zero", "this conclusion cannot be drawn from the information given"], "answer": 1, "exp": "Since applying the transition matrix to this vector produced the exact same vector, [0.6, 0.4] is the system's steady state (or equilibrium distribution) — it remains unchanged under further application of the matrix.", "hint": "Think about the defining property of a steady state: it doesn't change when the transition matrix is applied again."}, {"id": "srg122021", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Matrices — Leslie Matrices", "difficulty": "hard", "style": "standard", "paper": "G12-G2", "q": "Which best describes the relationship between the dominant eigenvalue of a Leslie matrix and the population's long-term fate?", "options": ["eigenvalues have no connection to population growth", "if the dominant eigenvalue is greater than 1, the population tends to grow; if less than 1, it tends to decline; if equal to 1, it tends toward stability", "the dominant eigenvalue only matters for very small populations", "a dominant eigenvalue of exactly 0 indicates explosive population growth"], "answer": 1, "exp": "The dominant eigenvalue of a Leslie matrix determines the population's long-term growth pattern: greater than 1 indicates growth, less than 1 indicates decline, and equal to 1 indicates long-term stability.", "hint": "Think about how repeated multiplication by a number greater than 1, less than 1, or equal to 1 would affect a quantity over time."}, {"id": "srg122022", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Matrices — Transition States", "difficulty": "hard", "style": "standard", "paper": "G12-G2", "q": "Which best describes a practical limitation of using a transition matrix model to predict population distributions far into the future?", "options": ["transition matrices are always perfectly accurate over any time scale", "the model assumes the transition rates remain constant over time, which may not hold true if real-world conditions change", "transition matrices cannot be used to predict anything about the future", "this type of model can only ever predict a single time period ahead"], "answer": 1, "exp": "A key limitation is that the model assumes transition rates remain constant over time, which may not hold true if real-world conditions (such as economic factors, environmental changes, or policy shifts) change in ways not captured by the original matrix.", "hint": "Think about whether the real-world rates a transition matrix is based on are likely to stay exactly the same forever."}, {"id": "srg122023", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Matrices — Transition States", "difficulty": "hard", "style": "standard", "paper": "G12-G2", "q": "A company tracks customer loyalty between two competing brands using a transition matrix. If Brand A currently retains 85% of its customers each year (losing 15% to Brand B), what value would appear in the corresponding position of the transition matrix?", "options": ["0.15", "0.5", "0.85", "1.0"], "answer": 2, "exp": "The proportion of Brand A customers who remain with Brand A (85%) is represented as 0.85 in the transition matrix.", "hint": "Convert the retention percentage directly into a decimal for the matrix entry."}, {"id": "srg122024", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Matrices — Transition States", "difficulty": "hard", "style": "standard", "paper": "G12-G2", "q": "Which best describes why summing each COLUMN of a transition matrix to check it equals 1 is an important verification step before using the matrix?", "options": ["this check has no real purpose", "it confirms that all individuals starting in a given state are accounted for somewhere in the next time period, with no individuals lost or created", "columns never need to sum to any particular value", "this check only applies to Leslie matrices, not standard transition matrices"], "answer": 1, "exp": "Checking that each column sums to 1 confirms that all individuals starting in a given state are fully accounted for in the next time period (distributed among all possible destination states), with none lost or created — an important consistency check for the model.", "hint": "Think about why every individual currently in a state needs to end up SOMEWHERE in the next period, with the probabilities adding up to certainty."}, {"id": "srg122025", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Matrices — Transition States", "difficulty": "hard", "style": "standard", "paper": "G12-G2", "q": "A transition matrix models weather as either 'Sunny' or 'Rainy'. If it is sunny today, there is a 75% chance it is sunny tomorrow. What value would appear in the matrix for 'sunny to rainy'?", "options": ["0.25", "0.50", "0.75", "1.00"], "answer": 0, "exp": "Since there is a 75% chance of remaining sunny, the remaining probability of switching from sunny to rainy is 100% − 75% = 25%, or 0.25.", "hint": "Since the two outcomes (staying sunny or switching to rainy) must add up to 1, subtract the given probability from 1."}, {"id": "srg123001", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Networks — Critical Path", "difficulty": "hard", "style": "standard", "paper": "G12-G3", "q": "A project has two possible paths from start to finish: Path 1 (activities A-B-D) takes 3+5+4=12 days, and Path 2 (activities A-C-D) takes 3+2+4=9 days. What is the length of the critical path?", "options": ["9 days", "11 days", "12 days", "21 days"], "answer": 2, "exp": "The critical path is the LONGEST path through the network, since this determines the minimum time needed to complete the whole project. Path 1 (12 days) is longer than Path 2 (9 days), so the critical path is 12 days.", "hint": "The critical path is always the longest path, not the shortest."}, {"id": "srg123002", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Networks — Critical Path", "difficulty": "hard", "style": "standard", "paper": "G12-G3", "q": "Using the same project (Path 1 = 12 days critical path, Path 2 = 9 days), what is the float (slack) of activity C, which lies on the non-critical path?", "options": ["0 days", "2 days", "3 days", "9 days"], "answer": 2, "exp": "Step 1: Float = critical path length − the path containing the activity = 12 − 9 = 3 days. Step 2: This means activity C's path has 3 days of spare time before it would delay the whole project.", "hint": "Subtract the length of the path containing this activity from the length of the critical path."}, {"id": "srg123003", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Networks — Critical Path Crashing", "difficulty": "hard", "style": "standard", "paper": "G12-G3", "q": "What does 'crashing' a project mean, in the context of critical path analysis?", "options": ["allowing the project to run over time with no consequences", "deliberately reducing the duration of one or more activities (often at extra cost) to shorten the overall project completion time", "cancelling the project entirely", "a term with no specific meaning in project management"], "answer": 1, "exp": "\"Crashing\" a project means deliberately reducing the duration of one or more activities, often by allocating extra resources or cost, in order to shorten the overall project completion time.", "hint": "Think about deliberately speeding up a project, often by spending extra money or resources."}, {"id": "srg123004", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Networks — Critical Path Crashing", "difficulty": "hard", "style": "standard", "paper": "G12-G3", "q": "Why does crashing a NON-CRITICAL activity generally fail to reduce a project's overall completion time?", "options": ["non-critical activities always have zero duration", "since non-critical activities are not on the longest path, reducing their duration does not affect the overall (longest) path length, until their float is fully used up", "crashing always reduces the overall completion time, regardless of which activity is crashed", "non-critical activities cannot be crashed at all"], "answer": 1, "exp": "Since non-critical activities are not on the longest (critical) path, reducing their duration does not shorten the project's overall completion time — unless the reduction is large enough to exceed their available float and shift the critical path.", "hint": "Think about why shortening a path that's already shorter than the critical path wouldn't change the OVERALL longest path."}, {"id": "srg123005", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Networks — Critical Path Crashing", "difficulty": "hard", "style": "standard", "paper": "G12-G3", "q": "If crashing a critical path activity by 1 day costs $500, and crashing reduces overall project completion time by 1 day per day crashed, what would it cost to reduce a 12-day critical path project to 10 days?", "options": ["$500", "$1000", "$1500", "$2000"], "answer": 1, "exp": "Step 1: Reducing from 12 days to 10 days requires crashing by 2 days. Step 2: 2 days × $500 per day = $1000.", "hint": "Find how many days need to be crashed, then multiply by the cost per day."}, {"id": "srg123006", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Networks — Assignment Problems", "difficulty": "hard", "style": "standard", "paper": "G12-G3", "q": "In an assignment problem, three workers must each be assigned to exactly one of three tasks, minimising total cost. What is this type of problem an example of?", "options": ["a critical path problem", "a bipartite matching (allocation) problem", "a Eulerian path problem", "a Leslie matrix problem"], "answer": 1, "exp": "An assignment problem, where workers are matched to tasks they are qualified for, is a type of bipartite matching (allocation) problem.", "hint": "Think about matching items from one group (workers) to items from another group (tasks)."}, {"id": "srg123007", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Networks — Assignment Problems", "difficulty": "hard", "style": "standard", "paper": "G12-G3", "q": "A cost matrix for assigning 3 workers to 3 tasks is given. Using the Hungarian algorithm (or similar method), the optimal assignment achieves a total minimum cost of $29. What does this total represent?", "options": ["the average cost per worker", "the maximum possible cost for any assignment", "the minimum possible total cost, summing the cost of each worker's assigned task", "the cost of assigning all workers to the same task"], "answer": 2, "exp": "The total of $29 represents the minimum possible total cost, found by summing the individual cost of each worker's optimally assigned task across the whole assignment.", "hint": "Think about adding up the cost for each individual worker-task pairing in the BEST possible overall assignment."}, {"id": "srg123008", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Networks — Flow Problems", "difficulty": "hard", "style": "standard", "paper": "G12-G3", "q": "In a flow network representing a system of pipes, what does the 'capacity' of an edge represent?", "options": ["the length of the pipe", "the maximum flow rate that edge (pipe) can carry", "the number of pipes in the network", "the cost of building that pipe"], "answer": 1, "exp": "The capacity of an edge represents the maximum flow rate (such as litres per minute) that edge can carry.", "hint": "Think about the maximum amount that can pass through a single pipe at once."}, {"id": "srg123009", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Networks — Flow Problems", "difficulty": "hard", "style": "standard", "paper": "G12-G3", "q": "What does the 'maximum flow' from a source to a sink in a flow network represent?", "options": ["the total number of edges in the network", "the greatest possible total flow that can be sent from source to sink, limited by the capacities along the way", "the shortest path between source and sink", "the average capacity of all edges in the network"], "answer": 1, "exp": "Maximum flow represents the greatest possible total flow that can be sent from the source to the sink, limited by the capacity constraints of the edges (particularly any 'bottleneck' edges) along the possible paths.", "hint": "Think about the overall limit on how much can flow through the entire network from start to end."}, {"id": "srg123010", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Networks — Flow Problems", "difficulty": "hard", "style": "standard", "paper": "G12-G3", "q": "What is a 'cut' in a flow network, in the context of the max-flow min-cut theorem?", "options": ["a single edge removed at random", "a set of edges that, if removed, would completely separate the source from the sink", "the total number of vertices in the network", "a synonym for the network's maximum flow"], "answer": 1, "exp": "A cut is a set of edges that, if removed, would completely separate the source from the sink, disconnecting any possible flow path between them.", "hint": "Think about a set of edges that would need to be 'cut' to completely block all paths from source to sink."}, {"id": "srg123011", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Networks — Flow Problems", "difficulty": "hard", "style": "standard", "paper": "G12-G3", "q": "According to the max-flow min-cut theorem, how are the maximum flow and the minimum cut of a network related?", "options": ["they are unrelated values", "the maximum possible flow through a network equals the capacity of its minimum cut", "the maximum flow is always greater than the minimum cut's capacity", "the minimum cut is always greater than the maximum flow"], "answer": 1, "exp": "The max-flow min-cut theorem states that the maximum possible flow through a network is exactly equal to the total capacity of its minimum cut (the smallest-capacity set of edges separating source from sink).", "hint": "This well-known theorem states these two quantities are exactly equal."}, {"id": "srg123012", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Networks — Critical Path", "difficulty": "hard", "style": "standard", "paper": "G12-G3", "q": "In a critical path network, an activity has an earliest start time (EST) of 5 days and a latest start time (LST) of 8 days. What is its float?", "options": ["3 days", "5 days", "8 days", "13 days"], "answer": 0, "exp": "Step 1: Float = latest start time − earliest start time. Step 2: 8 − 5 = 3 days.", "hint": "Subtract the earliest start time from the latest start time."}, {"id": "srg123013", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Networks — Assignment Problems", "difficulty": "hard", "style": "standard", "paper": "G12-G3", "q": "Which best describes why bipartite matching algorithms are useful beyond simply assigning workers to tasks?", "options": ["bipartite matching has no other practical applications", "similar matching problems arise in many contexts, such as matching students to university places, organs to transplant recipients, or advertisements to webpages", "bipartite matching only works for exactly 2 items in each group", "bipartite matching cannot be solved using any systematic algorithm"], "answer": 1, "exp": "Bipartite matching problems arise in many real-world contexts beyond worker-task assignment, such as matching students to university places, organs to transplant recipients, or online advertisements to relevant webpages.", "hint": "Think about other situations involving matching items from two distinct groups together."}, {"id": "srg123014", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Networks — Critical Path Crashing", "difficulty": "hard", "style": "standard", "paper": "G12-G3", "q": "In project crashing, the 'cost slope' of an activity refers to what?", "options": ["the natural duration of the activity with no crashing applied", "the additional cost per unit of time saved by crashing that particular activity", "the float of the activity", "the total project budget"], "answer": 1, "exp": "The cost slope represents the additional cost per unit of time saved by crashing a particular activity, helping project managers identify which activities offer the cheapest time savings.", "hint": "Think about a rate: cost increase divided by time saved, for a specific activity."}, {"id": "srg123015", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Networks — Critical Path Crashing", "difficulty": "hard", "style": "standard", "paper": "G12-G3", "q": "When deciding which activities to crash first to reduce overall project time at minimum extra cost, which activities should generally be prioritised?", "options": ["non-critical activities with the highest float", "critical path activities with the lowest cost slope (cheapest cost per day saved)", "activities at the very start of the project, regardless of cost", "activities with the longest natural duration, regardless of cost"], "answer": 1, "exp": "To reduce overall project time at minimum extra cost, project managers should prioritise crashing critical path activities with the lowest cost slope (the cheapest cost per day of time saved), since crashing non-critical activities has no effect on overall completion time.", "hint": "Remember that only critical path activities affect overall completion time, and look for the cheapest way to save time among those."}, {"id": "srg123016", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Networks — Flow Problems", "difficulty": "hard", "style": "standard", "paper": "G12-G3", "q": "A flow network has a single bottleneck edge with a capacity of 20 units, through which all flow from source to sink must pass. What is the maximum flow through the entire network?", "options": ["10 units", "20 units", "40 units", "unlimited"], "answer": 1, "exp": "Since all flow must pass through this single bottleneck edge, the maximum flow through the entire network cannot exceed the bottleneck's capacity of 20 units, regardless of the capacity of any other edges.", "hint": "Think about how a single narrow point that all flow must pass through limits the entire system's capacity."}, {"id": "srg123017", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Networks — Assignment Problems", "difficulty": "hard", "style": "standard", "paper": "G12-G3", "q": "In an assignment problem cost matrix, if one worker is equally unqualified for all tasks (very high cost for every option), what does this typically indicate about the optimal solution?", "options": ["that worker will always be assigned the cheapest available task regardless of overall cost", "the optimal solution will try to assign that worker to whichever task minimises their (still high) cost, while other workers are optimally matched to their best options", "that worker will never be included in any valid assignment", "the entire assignment problem becomes impossible to solve"], "answer": 1, "exp": "Even if one worker has high costs for every task, a complete assignment still requires assigning them to one task — the optimal solution will assign them to whichever task minimises their (still relatively high) cost, while the other workers are optimally matched elsewhere.", "hint": "Remember that every worker must be assigned to exactly one task in a complete assignment, even if all their options are relatively costly."}, {"id": "srg123018", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Networks — Critical Path", "difficulty": "hard", "style": "standard", "paper": "G12-G3", "q": "Which best describes the purpose of an 'activity-on-arc' network diagram in critical path analysis?", "options": ["it has no specific function in project planning", "it represents each activity as an arc (edge) between two nodes representing events, showing the sequence and dependencies between activities", "it only shows the total project cost", "it represents only the activities NOT on the critical path"], "answer": 1, "exp": "An activity-on-arc diagram represents each activity as an arc (edge) connecting two nodes (representing events or milestones), clearly showing the sequence and dependency relationships between activities.", "hint": "Think about how representing each TASK as a connecting line between two POINTS (events) helps show the order of a project's activities."}, {"id": "srg123019", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Networks — Critical Path Crashing", "difficulty": "hard", "style": "standard", "paper": "G12-G3", "q": "A project's critical path is 20 days. After crashing one activity by 2 days at a cost of $800, a new critical path emerges that is still 19 days long (since crashing revealed a previously second-longest path). What does this suggest?", "options": ["the crashing had no effect on the project at all", "the crashing reduced the original critical path, but a different path has now become the new constraint, limiting further improvement from that specific activity", "the project must now be restarted entirely", "this situation can never occur in practice"], "answer": 1, "exp": "This suggests that while crashing successfully reduced the original critical path, a different path (previously the second-longest) has now become the new critical path, meaning further reductions to the original path's activities won't help until this new critical path is also addressed.", "hint": "Think about what happens when shortening the longest path reveals a different path that is now the longest instead."}, {"id": "srg123020", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Networks — Minimum Spanning Tree", "difficulty": "hard", "style": "standard", "paper": "G12-G3", "q": "Which best describes why minimum spanning tree algorithms (like Prim's or Kruskal's algorithm) are useful for designing infrastructure networks, such as electricity or water supply?", "options": ["these algorithms have no real practical application", "they find the lowest-cost way to connect all required locations without unnecessary redundant connections, useful for minimising infrastructure costs", "these algorithms only work for networks with exactly 2 vertices", "these algorithms always produce the same result regardless of the costs involved"], "answer": 1, "exp": "Minimum spanning tree algorithms find the lowest-cost way to connect all required locations without unnecessary redundant connections, which is directly useful for minimising the cost of infrastructure networks like electricity or water supply.", "hint": "Think about connecting many locations as cheaply as possible, without any unnecessary extra connections."}, {"id": "srg123021", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Networks — Critical Path", "difficulty": "hard", "style": "standard", "paper": "G12-G3", "q": "In a project network, activity E has an earliest finish time (EFT) of 12 days and the project's critical path is 15 days. If E is NOT on the critical path, and its latest finish time (LFT) is 15 days, what is its float?", "options": ["0 days", "3 days", "12 days", "15 days"], "answer": 1, "exp": "Step 1: Float = latest finish time − earliest finish time. Step 2: 15 − 12 = 3 days.", "hint": "Subtract the earliest finish time from the latest finish time."}, {"id": "srg123022", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Networks — Critical Path Crashing", "difficulty": "hard", "style": "standard", "paper": "G12-G3", "q": "Which best describes why a project manager might choose NOT to crash a project, even if it's technically possible to reduce its completion time?", "options": ["crashing is always free, so there is never a reason not to do it", "the additional cost of crashing may outweigh the practical benefit of finishing earlier, especially if there's no urgent deadline", "crashing always makes a project take longer, not shorter", "project managers are never allowed to crash a project under any circumstances"], "answer": 1, "exp": "Crashing typically involves additional costs (such as overtime pay or extra resources), so a project manager might reasonably decide that the cost of crashing outweighs the practical benefit of finishing earlier, especially without an urgent deadline.", "hint": "Think about a cost-benefit trade-off: is paying extra to finish early actually worth it in every situation?"}, {"id": "srg123023", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Networks — Decision Mathematics", "difficulty": "hard", "style": "standard", "paper": "G12-G3", "q": "Which best describes the relationship between critical path analysis and assignment problems, in terms of their general purpose within decision mathematics?", "options": ["they are unrelated topics with no shared purpose", "both are optimisation techniques: critical path analysis optimises project TIMING, while assignment problems optimise the MATCHING of resources to tasks", "both techniques solve exactly the same type of problem", "neither technique has any real-world application"], "answer": 1, "exp": "Both are optimisation techniques within decision mathematics, but with different focuses: critical path analysis optimises project timing and scheduling, while assignment problems optimise the matching of resources (like workers) to tasks.", "hint": "Think about what specific aspect of a real-world problem each technique is actually trying to optimise."}, {"id": "srg123024", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Networks — Critical Path Crashing", "difficulty": "hard", "style": "standard", "paper": "G12-G3", "q": "A project has a critical path of 25 days. The project sponsor offers a $5000 bonus if the project finishes in 22 days or fewer. If crashing costs $600 per day saved on the critical path, should the team pursue this bonus?", "options": ["yes, since crashing 3 days would cost $1800, which is less than the $5000 bonus, making it worthwhile", "no, crashing is never worth pursuing under any circumstances", "yes, but only if the project is already late", "this cannot be determined without more information about non-critical activities"], "answer": 0, "exp": "Step 1: Reducing from 25 to 22 days requires crashing 3 days. Step 2: Cost = 3 × $600 = $1800, which is well below the $5000 bonus, making it financially worthwhile to pursue.", "hint": "Calculate the total crashing cost for the required time reduction, then compare it to the bonus on offer."}, {"id": "srg123025", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Networks — Critical Path", "difficulty": "hard", "style": "standard", "paper": "G12-G3", "q": "Which best describes a 'dummy activity' in an activity-on-arc project network diagram?", "options": ["an activity with zero duration, used only to correctly represent dependency relationships between other activities", "an activity that has been completed ahead of schedule", "an activity that has been removed from the project entirely", "an activity with no dependencies at all"], "answer": 0, "exp": "A dummy activity has zero duration and is used purely to correctly represent dependency relationships between other activities, when the diagram's structure would otherwise misrepresent those dependencies.", "hint": "Think about an activity included only to fix the LOGIC of the diagram, not to represent real, time-consuming work."}, {"id": "srg124001", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Bivariate Data — Correlation", "difficulty": "hard", "style": "standard", "paper": "G12-G4", "q": "What does a correlation coefficient (r) of 0.9 indicate about the relationship between two variables?", "options": ["a weak negative relationship", "almost no relationship at all", "a strong positive relationship", "a perfect negative relationship"], "answer": 2, "exp": "A correlation coefficient of 0.9 (close to +1) indicates a strong positive relationship between the two variables.", "hint": "Remember that values close to +1 indicate a strong positive relationship, while values close to -1 indicate a strong negative one."}, {"id": "srg124002", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Bivariate Data — Regression", "difficulty": "hard", "style": "standard", "paper": "G12-G4", "q": "For the data points (1,3), (2,5), (3,4), (4,6), (5,8), the least-squares regression line has a gradient of approximately 1.1 and a y-intercept of approximately 1.9. Using this line, what value would be predicted for x=6?", "options": ["7.5", "8.0", "8.5", "9.0"], "answer": 2, "exp": "Step 1: Substitute x=6 into y=1.1x+1.9. Step 2: 1.1×6+1.9 = 6.6+1.9 = 8.5.", "hint": "Substitute the given x-value into the regression equation y = gradient×x + intercept."}, {"id": "srg124003", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Bivariate Data — Regression", "difficulty": "hard", "style": "standard", "paper": "G12-G4", "q": "In the equation of a least-squares regression line, y = mx + c, what does 'm' represent?", "options": ["the y-intercept", "the gradient (slope) of the line, representing the average change in y for each one-unit increase in x", "the correlation coefficient", "the coefficient of determination"], "answer": 1, "exp": "In a regression equation, 'm' represents the gradient (slope), indicating the average change in the response variable (y) for each one-unit increase in the explanatory variable (x).", "hint": "Think about the value that describes how steeply the line rises or falls."}, {"id": "srg124004", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Bivariate Data — Coefficient of Determination", "difficulty": "hard", "style": "standard", "paper": "G12-G4", "q": "What does the 'coefficient of determination' (r²) represent in the context of a regression analysis?", "options": ["the gradient of the regression line", "the proportion of variation in the response variable that can be explained by the explanatory variable", "the y-intercept of the regression line", "the total number of data points"], "answer": 1, "exp": "The coefficient of determination (r²) represents the proportion of variation in the response variable that can be explained by its relationship with the explanatory variable, expressed as a value between 0 and 1.", "hint": "This value tells you how much of the variation in one variable can be 'explained' by the other."}, {"id": "srg124005", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Bivariate Data — Coefficient of Determination", "difficulty": "hard", "style": "standard", "paper": "G12-G4", "q": "If a correlation coefficient is r=0.9, what is the coefficient of determination (r²), and how would you interpret it?", "options": ["r²=0.81, meaning 81% of the variation in y can be explained by x", "r²=0.9, meaning 90% of the data is identical", "r²=1.8, meaning the relationship is twice as strong as a perfect correlation", "r²=0.45, meaning only 45% of the data is reliable"], "answer": 0, "exp": "Step 1: r² = 0.9² = 0.81. Step 2: This means approximately 81% of the variation in the response variable can be explained by its relationship with the explanatory variable.", "hint": "Square the correlation coefficient to find the coefficient of determination."}, {"id": "srg124006", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Bivariate Data — Regression", "difficulty": "hard", "style": "standard", "paper": "G12-G4", "q": "Which best describes 'extrapolation' when using a regression line to make predictions?", "options": ["making a prediction for a value WITHIN the range of the original data", "making a prediction for a value OUTSIDE the range of the original data, which carries greater risk of inaccuracy", "a synonym for the correlation coefficient", "a technique that always produces highly accurate predictions"], "answer": 1, "exp": "Extrapolation involves making a prediction for a value outside the range of the original data, which carries a greater risk of inaccuracy, since the relationship observed within the data range may not continue to hold true beyond it.", "hint": "Think about predicting a value FAR beyond the range of data you actually collected and observed."}, {"id": "srg124007", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Time Series — Moving Averages", "difficulty": "hard", "style": "standard", "paper": "G12-G4", "q": "Which best describes a 3-point moving average, used in time series analysis?", "options": ["the average of the first 3 data points only, used for the entire series", "the average of each group of 3 consecutive data points, used to smooth out short-term fluctuations and reveal underlying trends", "a synonym for the correlation coefficient", "a method that always produces the original, unsmoothed data"], "answer": 1, "exp": "A 3-point moving average calculates the average of each group of 3 consecutive data points, sliding through the series, which helps smooth out short-term fluctuations and reveal the underlying long-term trend.", "hint": "Think about averaging a small, sliding 'window' of consecutive data points, rather than the whole data set at once."}, {"id": "srg124008", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Time Series — Moving Averages", "difficulty": "hard", "style": "standard", "paper": "G12-G4", "q": "Given the time series data 10, 12, 14, 11, 13, 15, 16, what is the first value of the 3-point moving average (averaging the first three values)?", "options": ["10.7", "11.0", "12.0", "12.3"], "answer": 2, "exp": "Step 1: Average the first three values: (10+12+14)÷3. Step 2: 36÷3=12.0.", "hint": "Add the first three values together, then divide by 3."}, {"id": "srg124009", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Time Series — Seasonality", "difficulty": "hard", "style": "standard", "paper": "G12-G4", "q": "Which best describes 'seasonality' in time series data?", "options": ["a one-time, unpredictable event affecting the data", "a regular, repeating pattern in the data that occurs at consistent intervals (such as each quarter or each year)", "a steady, long-term increase or decrease in the data with no repeating pattern", "random noise with absolutely no discernible pattern"], "answer": 1, "exp": "Seasonality refers to a regular, repeating pattern in time series data that occurs at consistent intervals, such as increased retail sales every December, repeating predictably year after year.", "hint": "Think about a pattern that repeats predictably at the same time each cycle, like a particular season each year."}, {"id": "srg124010", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Time Series — Seasonality", "difficulty": "hard", "style": "standard", "paper": "G12-G4", "q": "Which best describes the purpose of 'deseasonalising' time series data?", "options": ["deseasonalising has no practical purpose", "removing the seasonal pattern from the data to more clearly reveal the underlying trend", "deliberately adding a seasonal pattern to data that doesn't naturally have one", "a synonym for calculating a moving average"], "answer": 1, "exp": "Deseasonalising removes the seasonal pattern from time series data, making it easier to identify and analyse the underlying long-term trend without the distraction of regular seasonal fluctuations.", "hint": "Think about 'removing' a known repeating pattern so you can see the bigger underlying trend more clearly."}, {"id": "srg124011", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Time Series — Seasonal Index", "difficulty": "hard", "style": "standard", "paper": "G12-G4", "q": "A 'seasonal index' for a particular quarter is calculated as 1.2. What does this indicate?", "options": ["that quarter's values are typically 20% below the overall average", "that quarter's values are typically 20% above the overall average", "that quarter accounts for exactly 1.2% of total annual sales", "seasonal indices have no specific numerical interpretation"], "answer": 1, "exp": "A seasonal index of 1.2 indicates that, typically, this quarter's values are 20% above the overall average (since the index is greater than 1).", "hint": "An index greater than 1 indicates values above average; less than 1 indicates values below average."}, {"id": "srg124012", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Time Series — Seasonal Index", "difficulty": "hard", "style": "standard", "paper": "G12-G4", "q": "If a quarter's actual sales are $50,000 and its seasonal index is 1.25, what would the deseasonalised value be?", "options": ["$32,500", "$40,000", "$50,000", "$62,500"], "answer": 1, "exp": "Step 1: Deseasonalised value = actual value ÷ seasonal index. Step 2: $50,000 ÷ 1.25 = $40,000.", "hint": "Divide the actual value by the seasonal index to remove the seasonal effect."}, {"id": "srg124013", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Bivariate Data — Correlation vs Causation", "difficulty": "hard", "style": "standard", "paper": "G12-G4", "q": "Which best describes why correlation between two variables does NOT necessarily imply that one causes the other?", "options": ["correlation always proves causation with no exceptions", "a third, unmeasured factor might independently influence both variables, or the relationship could simply be coincidental", "causation can only ever be determined through correlation analysis", "this caution applies only to negative correlations, not positive ones"], "answer": 1, "exp": "A third, unmeasured factor might independently influence both variables (creating an apparent relationship without direct causation), or the observed relationship could simply be coincidental, especially with a small data set.", "hint": "Think about other possible explanations for why two variables might appear related, besides one directly causing the other."}, {"id": "srg124014", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Bivariate Data — Concepts", "difficulty": "hard", "style": "standard", "paper": "G12-G4", "q": "In bivariate data analysis, which variable is conventionally plotted on the horizontal (x) axis?", "options": ["the response variable", "the explanatory (independent) variable", "whichever variable has larger values", "there is no convention for this"], "answer": 1, "exp": "The explanatory (independent) variable is conventionally plotted on the horizontal (x) axis, with the response (dependent) variable on the vertical (y) axis.", "hint": "Think about the variable believed to potentially INFLUENCE the other, which is typically placed on the horizontal axis."}, {"id": "srg124015", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Bivariate Data — Residuals", "difficulty": "hard", "style": "standard", "paper": "G12-G4", "q": "Which best describes a 'residual' in regression analysis?", "options": ["the gradient of the regression line", "the difference between an observed data value and the value predicted by the regression line", "the correlation coefficient", "the total number of data points used in the analysis"], "answer": 1, "exp": "A residual is the difference between an observed data value and the value predicted by the regression line for that same x-value (residual = observed − predicted).", "hint": "Think about how far off the regression line's prediction was from what actually happened."}, {"id": "srg124016", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Bivariate Data — Residuals", "difficulty": "hard", "style": "standard", "paper": "G12-G4", "q": "Why are residual plots useful for checking whether a linear regression model is appropriate for a data set?", "options": ["residual plots have no diagnostic value", "if residuals show a clear pattern (rather than being randomly scattered), this suggests a linear model may not be appropriate for the data", "residual plots can only be used with time series data, not bivariate data", "residual plots always confirm that a linear model is appropriate, regardless of their appearance"], "answer": 1, "exp": "If a residual plot shows a clear pattern (such as a curve), rather than residuals being randomly scattered around zero, this suggests the relationship may not actually be linear, and a different model might fit the data better.", "hint": "Think about what a clear, non-random PATTERN in the residuals (rather than random scatter) might suggest about the model's fit."}, {"id": "srg124017", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Time Series — Components", "difficulty": "hard", "style": "standard", "paper": "G12-G4", "q": "A time series shows an overall upward trend with regular quarterly fluctuations layered on top of it. Which best describes this combination of components?", "options": ["trend and seasonality, two common components of time series data", "only random noise, with no identifiable trend or pattern", "only seasonality, with no underlying trend", "this combination cannot occur in real time series data"], "answer": 0, "exp": "This describes a combination of trend (the overall upward direction) and seasonality (the regular quarterly fluctuations), two of the most common components analysed in time series data.", "hint": "Think about the two distinct patterns being described: a steady overall direction, plus a regularly repeating fluctuation."}, {"id": "srg124018", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Time Series — Components", "difficulty": "hard", "style": "standard", "paper": "G12-G4", "q": "Which best describes 'irregular' (or random) variation in time series data?", "options": ["a predictable, repeating seasonal pattern", "unpredictable fluctuations that cannot be attributed to trend or seasonality, often caused by one-off or unusual events", "the overall long-term direction of the data", "a synonym for the moving average"], "answer": 1, "exp": "Irregular (or random) variation refers to unpredictable fluctuations in time series data that cannot be attributed to trend or seasonality, often resulting from one-off, unusual events.", "hint": "Think about fluctuations that don't fit any predictable pattern, often due to unexpected, one-off events."}, {"id": "srg124019", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Time Series — Moving Averages", "difficulty": "hard", "style": "standard", "paper": "G12-G4", "q": "A 5-point moving average is used instead of a 3-point moving average on the same time series. What is the likely effect on the smoothness of the resulting trend line?", "options": ["the 5-point average will be less smooth than the 3-point average", "the 5-point average will generally be smoother (showing less short-term fluctuation) than the 3-point average", "there will be no difference between the two", "moving averages of different lengths always produce identical results"], "answer": 1, "exp": "A 5-point moving average generally produces a smoother trend line than a 3-point moving average, since averaging over a larger number of points further reduces the impact of short-term fluctuations.", "hint": "Think about how averaging over a LARGER window of data points affects the smoothness of the result."}, {"id": "srg124020", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Bivariate Data — Regression", "difficulty": "hard", "style": "standard", "paper": "G12-G4", "q": "Which best describes why it can be misleading to use a regression line fitted to data from one context to make predictions in a very different context (such as a different country or time period)?", "options": ["regression lines are always universally applicable, regardless of context", "the relationship between variables observed in one context may not hold true in a different context with different underlying conditions", "this issue never actually arises in real statistical analysis", "regression lines cannot be used to make any predictions at all"], "answer": 1, "exp": "The relationship between variables observed in one specific context (such as a particular country, time period, or population) may not hold true in a different context, where underlying conditions and influences could be quite different.", "hint": "Think about whether a relationship observed in one specific setting can always be safely assumed to apply in a completely different setting."}, {"id": "srg124021", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Bivariate Data — Regression", "difficulty": "hard", "style": "standard", "paper": "G12-G4", "q": "Which best describes the 'least-squares' method used to fit a regression line to bivariate data?", "options": ["it selects the line that minimises the total of the residuals (without squaring them)", "it selects the line that minimises the sum of the SQUARED residuals, the vertical distances between observed points and the line", "it selects the line that maximises the correlation coefficient directly", "it selects the line passing through the most data points exactly"], "answer": 1, "exp": "The least-squares method selects the regression line that minimises the sum of the squared residuals (the squared vertical distances between each observed data point and the line), which is why it's called 'least squares'.", "hint": "Think about why squaring the residuals (rather than just adding them directly) is part of this method's name and approach."}, {"id": "srg124022", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Bivariate Data — Correlation", "difficulty": "hard", "style": "standard", "paper": "G12-G4", "q": "A correlation coefficient of r=-0.85 is found between hours of television watched and hours of physical exercise per week. What does this suggest?", "options": ["more television watching is associated with more exercise", "more television watching is associated with less exercise, though this doesn't necessarily prove television watching directly causes less exercise", "there is no meaningful relationship between these two variables", "television watching directly and definitely causes reduced exercise"], "answer": 1, "exp": "A correlation of -0.85 (close to -1) suggests a strong negative relationship: more television watching is associated with less exercise, though this correlation alone doesn't prove that watching television directly causes reduced exercise.", "hint": "Think about both the strength and direction of this correlation, and remember the distinction between correlation and proven causation."}, {"id": "srg124023", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Time Series — Applications", "difficulty": "hard", "style": "standard", "paper": "G12-G4", "q": "Which best describes the purpose of using time series analysis in business forecasting?", "options": ["time series analysis has no practical business application", "identifying trend, seasonal, and irregular components in past data can help businesses forecast future demand, sales, or other key metrics", "time series analysis can only be used to analyse past data, never to forecast anything", "time series analysis always produces perfectly accurate forecasts with no uncertainty"], "answer": 1, "exp": "By identifying trend, seasonal, and irregular components in past data, businesses can make more informed forecasts about future demand, sales, or other key metrics, supporting better planning decisions.", "hint": "Think about how understanding past patterns might help a business plan for the future, even though forecasts are never perfectly certain."}, {"id": "srg124024", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Bivariate Data — Coefficient of Determination", "difficulty": "hard", "style": "standard", "paper": "G12-G4", "q": "Which best describes why a regression analysis with a very high r² value (e.g. r²=0.98) should still be interpreted cautiously?", "options": ["a high r² value guarantees the relationship is causal and will hold true in all future cases", "a high r² indicates a strong LINEAR fit to the observed data, but does not guarantee causation, or that the relationship holds outside the range of the data studied", "r² values above 0.9 are always statistically impossible", "this level of r² indicates the data must have been fabricated"], "answer": 1, "exp": "A high r² value indicates a strong linear fit to the specific data observed, but it does not guarantee that the relationship is causal, nor that it will continue to hold true outside the range of data actually studied (extrapolation risk).", "hint": "Think about what a strong statistical FIT to the data can and cannot tell you about cause-and-effect or future reliability."}, {"id": "srg124025", "state": "AU", "section": "sr_genmaths", "grade": "12", "topic": "Time Series — Seasonal Index", "difficulty": "hard", "style": "standard", "paper": "G12-G4", "q": "A company's quarterly sales data shows seasonal indices of 1.3 (summer), 0.7 (winter), 1.0 (spring), and 1.0 (autumn). If winter's actual sales are $21,000, what would the deseasonalised value be?", "options": ["$14,700", "$21,000", "$28,000", "$30,000"], "answer": 3, "exp": "Step 1: Deseasonalised value = actual value ÷ seasonal index. Step 2: $21,000 ÷ 0.7 = $30,000.", "hint": "Divide the actual value by the seasonal index for that specific quarter."}];